// -----------------------------------------------------------------------------
// Hash Generation (Random 3-block string with vowel in the middle: C-V-C)
// -----------------------------------------------------------------------------
const generateLinkHash = () => {
    const chars = "abcdefghijklmnopqrstuvwxyz"
    const vowels = "aeiou"

    // Generates a random 3-letter block in the format: Char-Vowel-Char
    const getRandomBlock = () => {
        const c1 = chars[Math.floor(Math.random() * chars.length)]
        const v = vowels[Math.floor(Math.random() * vowels.length)]
        const c2 = chars[Math.floor(Math.random() * chars.length)]
        return `${c1}${v}${c2}`
    }

    return `#${getRandomBlock()}-${getRandomBlock()}-${getRandomBlock()}`
}

// -----------------------------------------------------------------------------
// Audio Processing Helpers for Live API
// -----------------------------------------------------------------------------

function highPassFilter(
    audioData: Float32Array,
    sampleRate: number,
    cutoffFreq: number = 80
): Float32Array {
    const RC = 1.0 / (cutoffFreq * 2 * Math.PI)
    const dt = 1.0 / sampleRate
    const alpha = RC / (RC + dt)

    const filtered = new Float32Array(audioData.length)
    filtered[0] = audioData[0]

    for (let i = 1; i < audioData.length; i++) {
        filtered[i] =
            alpha * (filtered[i - 1] + audioData[i] - audioData[i - 1])
    }

    return filtered
}

function normalizeAudio(audioData: Float32Array): Float32Array {
    let maxAmp = 0
    for (let i = 0; i < audioData.length; i++) {
        const amp = Math.abs(audioData[i])
        if (amp > maxAmp) maxAmp = amp
    }

    if (maxAmp === 0) return audioData

    // Normalize to 0.7 to leave headroom and avoid clipping
    const normalized = new Float32Array(audioData.length)
    const targetLevel = 0.7
    const gain = targetLevel / maxAmp

    for (let i = 0; i < audioData.length; i++) {
        normalized[i] = audioData[i] * gain
    }

    return normalized
}

function detectVoiceActivity(
    audioData: Float32Array,
    threshold: number
): boolean {
    let sumSquares = 0
    let zeroCrossings = 0

    for (let i = 0; i < audioData.length; i++) {
        sumSquares += audioData[i] * audioData[i]

        if (i > 0 && audioData[i] * audioData[i - 1] < 0) {
            zeroCrossings++
        }
    }

    const rms = Math.sqrt(sumSquares / audioData.length)
    const zcr = zeroCrossings / audioData.length

    return rms > threshold && zcr > 0.01 && zcr < 0.5
}

function base64ToFloat32Array(base64: string): Float32Array {
    const binaryString = atob(base64)
    const len = binaryString.length
    const bytes = new Uint8Array(len)
    for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i)
    }
    const int16 = new Int16Array(bytes.buffer)
    const float32 = new Float32Array(int16.length)
    for (let i = 0; i < int16.length; i++) {
        float32[i] = int16[i] / 32768
    }
    return float32
}

function float32ToBase64(float32: Float32Array): string {
    const int16 = new Int16Array(float32.length)
    for (let i = 0; i < float32.length; i++) {
        const s = Math.max(-1, Math.min(1, float32[i]))
        int16[i] = s < 0 ? s * 0x8000 : s * 0x7fff
    }
    const bytes = new Uint8Array(int16.buffer)
    let binary = ""
    for (let i = 0; i < bytes.byteLength; i++) {
        binary += String.fromCharCode(bytes[i])
    }
    return btoa(binary)
}

