/** Extracts concatenated text from a Gemini generateContent response. */
function extractTextFromGeminiResponse(data: unknown): string {
    const parts = (data as any)?.candidates?.[0]?.content?.parts ?? []
    return parts
        .map((p: { text?: string }) => p.text ?? "")
        .join("")
        .trim()
}

/** First function call in a generateContent response (follow-up turns may include tools). */
function extractFunctionCallFromGeminiResponse(
    data: unknown
): { name: string; args: Record<string, unknown> } | null {
    const parts = (data as any)?.candidates?.[0]?.content?.parts ?? []
    for (const p of parts) {
        const fc = (p as { functionCall?: { name?: string; args?: unknown } })
            .functionCall
        if (fc?.name) {
            return {
                name: fc.name,
                args: (fc.args ?? {}) as Record<string, unknown>,
            }
        }
    }
    return null
}

/** Shortens huge `content` fields so Tools debug logs stay readable. */
function summarizeToolArgsForDebug(
    args: Record<string, unknown>,
    maxSlice = 200
): string {
    try {
        const copy: Record<string, unknown> = { ...args }
        const content = copy.content
        if (typeof content === "string" && content.length > maxSlice) {
            copy.content = `${content.slice(0, maxSlice)}… (${content.length} chars)`
        }
        return JSON.stringify(copy)
    } catch {
        return "(unserializable)"
    }
}

// Substrings like "AI" must not match case-insensitively inside "email", etc.
const KEYWORDS_REQUIRE_EXACT_CASE = new Set<string>(["AI"])

function keywordIndexInText(txt: string, kw: string): number {
    if (KEYWORDS_REQUIRE_EXACT_CASE.has(kw)) return txt.indexOf(kw)
    return txt.toLowerCase().indexOf(kw.toLowerCase())
}

// Inject `data-keyword-land` marker spans into resume HTML so the landing
// animation can locate each keyword's exact DOM position via a direct query
// instead of fragile TreeWalker + Range offset arithmetic.
// Only the FIRST occurrence of each keyword is marked so there's a single
// unambiguous target. Keywords inside existing HTML tags are never touched.
function markKeywordsInHtml(html: string, keywords: string[]): string {
    if (!html || keywords.length === 0) return html
    if (typeof document === "undefined") return html
    const tmp = document.createElement("div")
    tmp.innerHTML = html

    const claimed = new Set<string>()
    // Longer phrases first so e.g. "JavaScript" wins over "Java" in shared text.
    const sortedKw = [...keywords].sort(
        (a, b) => b.length - a.length || a.localeCompare(b)
    )

    const walker = document.createTreeWalker(tmp, NodeFilter.SHOW_TEXT)
    const hits: Array<{
        node: Text
        start: number
        end: number
        kw: string
    }> = []

    let node: Node | null
    while ((node = walker.nextNode())) {
        const textNode = node as Text
        const txt = textNode.textContent ?? ""
        for (const kw of sortedKw) {
            if (claimed.has(kw)) continue
            const idx = keywordIndexInText(txt, kw)
            if (idx !== -1) {
                hits.push({
                    node: textNode,
                    start: idx,
                    end: idx + kw.length,
                    kw,
                })
                claimed.add(kw)
            }
        }
    }

    // Process hits in reverse document order so earlier replacements don't
    // shift the offsets of later ones. Sort by node position is complex, so
    // instead we replace each node once (only one hit per node is needed).
    for (const { node: textNode, start, end, kw } of hits) {
        const parent = textNode.parentNode
        if (!parent) continue
        const txt = textNode.textContent ?? ""
        const before = document.createTextNode(txt.slice(0, start))
        const span = document.createElement("span")
        span.setAttribute("data-keyword-land", kw)
        span.textContent = txt.slice(start, end)
        const after = document.createTextNode(txt.slice(end))
        parent.insertBefore(before, textNode)
        parent.insertBefore(span, textNode)
        parent.insertBefore(after, textNode)
        parent.removeChild(textNode)
    }

    return tmp.innerHTML
}

/** Orbit pill strings captured from the job UI that appear in the resume body.
 * Uses case-insensitive matching so resume casing matches landing targets to
 * `item.word` (API / DOM capture may differ from model output), except tokens
 * in KEYWORDS_REQUIRE_EXACT_CASE (e.g. "AI" vs "email"). */
function capturedOrbitWordsInHtml(
    html: string,
    capturedWords: string[]
): string[] {
    if (!html) return []
    const lowerHtml = html.toLowerCase()
    const out: string[] = []
    const seen = new Set<string>()
    for (const w of capturedWords) {
        if (!w || seen.has(w)) continue
        const present = KEYWORDS_REQUIRE_EXACT_CASE.has(w)
            ? html.includes(w)
            : lowerHtml.includes(w.toLowerCase())
        if (present) {
            out.push(w)
            seen.add(w)
        }
    }
    return out
}

/** Map getComputedStyle().fontWeight to 100–900 for variable-font Motion interpolation. */
function parseCssFontWeight(raw: string): number {
    const s = (raw ?? "").trim().toLowerCase()
    if (s === "normal" || s === "regular") return 400
    if (s === "medium") return 500
    if (s === "semibold" || s === "demibold") return 600
    if (s === "bold") return 700
    const n = parseFloat(s)
    if (Number.isFinite(n)) return Math.min(900, Math.max(100, Math.round(n)))
    return 400
}

// DocEditor resume reveal uses 0.4s — orbit pills must stay until this finishes.
const RESUME_DOC_REVEAL_MS = 400

// --- INTERFACES ---

function KoahAdSlot({
    userMessage,
    aiResponse,
    messageId,
    onFill,
    onNoFill,
    style,
}: {
    userMessage: string
    aiResponse: string
    messageId: string
    onFill?: () => void
    onNoFill?: () => void
    style?: React.CSSProperties
}) {
    const isStatic = useIsStaticRenderer()
    const slotRef = React.useRef<HTMLDivElement>(null)

    React.useEffect(() => {
        if (typeof window === "undefined" || isStatic || !userMessage) return

        const target = slotRef.current
        if (!target) return

        // Poll until Koah SDK is ready (loaded async)
        const tryProcess = (attempts = 0) => {
            const koah = (window as any).koah
            if (!koah?.process) {
                if (attempts < 40)
                    setTimeout(() => tryProcess(attempts + 1), 200)
                return
            }
            koah.process(userMessage, aiResponse, "suffix", {
                target,
                messageId,
                onFill,
                onNoFill,
            })
        }
        tryProcess()
    }, []) // intentionally run once on mount

    if (isStatic) return null

    return <div ref={slotRef} style={{ width: "100%", ...style }} />
}

function AdCard({
    userMessage,
    aiResponse,
    messageId,
    onStatusChange,
    themeColors = darkColors,
}: {
    userMessage: string
    aiResponse: string
    messageId: string
    onStatusChange?: (status: "filled" | "unfilled" | "loading") => void
    themeColors?: typeof darkColors
}) {
    const [filled, setFilled] = React.useState(false)

    const handleFill = React.useCallback(() => {
        setFilled(true)
        onStatusChange?.("filled")
    }, [onStatusChange])

    const handleNoFill = React.useCallback(() => {
        onStatusChange?.("unfilled")
    }, [onStatusChange])

    return (
        <div
            style={{
                width: 300,
                flexShrink: 0,
                maxHeight: 384,
                paddingTop: 14,
                paddingBottom: 14,
                paddingLeft: 20,
                paddingRight: 16,
                background: themeColors.surface,
                overflow: "hidden",
                borderRadius: 28,
                justifyContent: "flex-start",
                alignItems: "center",
                gap: 4,
                // Keep in DOM so Koah can render into the slot; hide until filled
                display: filled ? "flex" : "none",
            }}
        >
            <div
                style={{
                    flex: "1 1 0",
                    height: "auto",
                    minHeight: 46.52,
                    width: "100%",
                }}
            >
                <KoahAdSlot
                    userMessage={userMessage}
                    aiResponse={aiResponse}
                    messageId={messageId}
                    onFill={handleFill}
                    onNoFill={handleNoFill}
                />
            </div>
        </div>
    )
}

function AdCarousel({
    userMessage,
    aiResponse,
    baseMessageId,
    themeColors = darkColors,
}: {
    userMessage: string
    aiResponse: string
    baseMessageId: string
    themeColors?: typeof darkColors
}) {
    const [ad1Filled, setAd1Filled] = React.useState(false)
    const [ad2Filled, setAd2Filled] = React.useState(false)

    const isVisible = ad1Filled || ad2Filled

    return (
        <div
            data-layer="custom ad carousel"
            className="CustomAdCarousel"
            style={{
                alignSelf: "stretch",
                justifyContent: "flex-start",
                alignItems: "flex-start",
                gap: 10,
                display: isVisible ? "flex" : "none",
                overflowX: "auto",
                overflowY: "hidden",
                paddingBottom: 4,
                scrollbarWidth: "none",
                msOverflowStyle: "none",
                marginBottom: 16,
                marginTop: 8,
                marginLeft: -4,
                width: "calc(100% + 48px)",
                paddingLeft: 0,
                paddingRight: 24,
                flexShrink: 0,
                minHeight: isVisible ? 76 : 0,
            }}
        >
            <style>{`
                .CustomAdCarousel::-webkit-scrollbar {
                    display: none;
                }
            `}</style>

            <AdCard
                userMessage={userMessage}
                aiResponse={aiResponse}
                messageId={`${baseMessageId}-1`}
                onStatusChange={(s) => setAd1Filled(s === "filled")}
                themeColors={themeColors}
            />

            <AdCard
                userMessage={userMessage}
                aiResponse={aiResponse}
                messageId={`${baseMessageId}-2`}
                onStatusChange={(s) => setAd2Filled(s === "filled")}
                themeColors={themeColors}
            />
        </div>
    )
}

/** Which developer overlay is shown (at most one). */
type DebugPanelMode = "off" | "p2p" | "tools"

interface Props {
    /** Curastem Worker base URL (maps key, Gemini proxy, Live token). Default api.curastem.org. */
    apiBaseUrl?: string
    skillsApiUrl?: string
    jobsApiUrl?: string
    systemPrompt: string
    accentColor: string
    model: string
    /**
     * Off | P2P (bottom-right: room, role, PeerJS/MQTT) | Tools & MCP (bottom-left: tool calls, jobs API).
     * Mutually exclusive — only one panel.
     */
    debugPanel?: DebugPanelMode
    showAds?: boolean
    koahPublisherId?: string
    defaultSuggestions?: string[]
}

/**
 * Agent skill — catalog item from Skills API.
 * API returns { id, name, description?, path? }; we map to this shape with
 * object: "skill" and placeholder version/created_at for compatibility.
 */
interface AgentSkill {
    id: string
    object: "skill"
    name: string
    description: string
    default_version: string
    latest_version: string
    created_at: number
}

interface Attachment {
    id: string
    file: File
    type: "image" | "video" | "file"
    previewUrl?: string
    name: string
    mimeType: string
}

/** Minimal job snippet stored on a message after a search_jobs tool call. */
interface JobSnippet {
    id: string
    title: string
    company: string
    company_logo?: string | null
    locations?: string[] | null
    employment_type?: string | null
    workplace_type?: string | null
    seniority_level?: string | null
    posted_at?: string | null
    apply_url?: string | null
    summary?: string | null
    salary?: string | null
    visa_sponsorship?: "yes" | "no" | null
}

interface Message {
    role: string
    text: string
    skills?: Array<{ id: string; name: string; description?: string }>
    attachments?: {
        type: "image" | "video" | "file"
        url?: string
        name?: string
        mimeType?: string
    }[]
    functionCall?: {
        name: string
        args: Record<string, any>
    }
    functionResponse?: {
        name: string
        response: any
    }
    /**
     * Set when the model created/updated a tool panel via delimiter streaming
     * ("app" or "doc"). Mirrors what functionCall.name provided for real tool
     * calls so renderChatSection can show the correct tag badge in both cases.
     */
    toolUsed?: "app" | "doc" | "resume" | "cover_letter"
    /** Stable id of the chat doc row this tool output created or updated (multi-doc chats). */
    docId?: string
    /** Jobs list from a search_jobs tool call, rendered as cards in chat. */
    jobs?: JobSnippet[]
    /** Job context chip — shown above user message bubble when sent with job details open. */
    jobContext?: {
        id: string
        title: string
        companyName: string
        logoUrl: string | null
    }
}

function dedupeJobRowsById(rows: any[] | undefined): any[] {
    if (!rows?.length) return []
    const out: any[] = []
    const seen = new Set<string>()
    for (const j of rows) {
        const id = j?.id
        if (typeof id !== "string" || seen.has(id)) continue
        seen.add(id)
        out.push(j)
    }
    return out
}

function applySearchJobsExcludeIds(
    params: URLSearchParams,
    seenJobIds: Set<string>,
    argsExclude: unknown
): void {
    const merged = new Set<string>(seenJobIds)
    if (argsExclude != null && argsExclude !== "") {
        const parts = Array.isArray(argsExclude)
            ? argsExclude
            : String(argsExclude).split(",")
        for (const p of parts) {
            const id = String(p).trim()
            if (id.length >= 4 && id.length <= 64) merged.add(id)
        }
    }
    if (merged.size === 0) return
    params.set("exclude_ids", [...merged].slice(0, 100).join(","))
}

function recordSearchJobsShownIds(
    seen: Set<string>,
    snippets: Array<{ id: string }>
): void {
    for (const s of snippets) {
        if (s.id) seen.add(s.id)
    }
}

/** Merge query + keywords into GET /jobs `title` (job title substring — not company name). */
function buildJobsApiTitle(
    query: unknown,
    keywords: unknown
): string | undefined {
    const a = typeof query === "string" ? query.trim() : ""
    const b = typeof keywords === "string" ? keywords.trim() : ""
    if (!a && !b) return undefined
    if (!a) return b
    if (!b) return a
    return `${a} ${b}`
}

const SEARCH_JOBS_MAX_POSTED_DAYS = 30

/**
 * Maps tool arg `posted_within_days` to GET /jobs `since` (unix seconds).
 * When omitted, returns undefined so the API does not apply a hard recency cutoff —
 * results are still ordered newest-first (`posted_at DESC`).
 */
function postedSinceUnixFromSearchJobsArg(raw: unknown): number | undefined {
    if (raw == null || raw === "") return undefined
    const n = Number(raw)
    if (!Number.isFinite(n) || n <= 0) return undefined
    const days = Math.min(
        Math.max(Math.floor(n), 1),
        SEARCH_JOBS_MAX_POSTED_DAYS
    )
    return Math.floor(Date.now() / 1000) - days * 86400
}

const NEAR_ME_USER_MESSAGE_RE =
    /\b(near me|nearby|around me|close to me|jobs around|local jobs|in my area|jobs near|near my|in this area|around here)\b/i

/** Model often passes location: "near me" without the user message being in the same string — detect both. */
const NEAR_ME_LOCATION_ARG_RE =
    /\b(near me|nearby|around me|around here|close to me|local jobs|in my area|jobs near|near my|in this area)\b|^here$/i

const SEARCH_JOBS_NEAR_ME_RADIUS_KM = "40"

function locationArgImpliesNearMe(
    args: Record<string, unknown>,
    params: URLSearchParams
): boolean {
    const fromArgs =
        typeof args.location === "string" ? args.location.trim() : ""
    const fromParams = params.get("location")?.trim() ?? ""
    const s = fromArgs || fromParams
    if (!s) return false
    return NEAR_ME_LOCATION_ARG_RE.test(s)
}

/** When refs are cold, resolve IP coords the same way as the lazy useEffect (search_jobs can run first). */
async function fetchJobsProxyGeoCoords(
    jobsApiUrl: string | null | undefined
): Promise<{ lat: number; lng: number } | null> {
    if (!jobsApiUrl) return null
    const base = jobsApiUrl.replace(/\/$/, "")
    try {
        const ctrl = new AbortController()
        const t = setTimeout(() => ctrl.abort(), 5000)
        const r = await fetch(`${base}/geo`, { signal: ctrl.signal })
        clearTimeout(t)
        if (!r.ok) return null
        const d = (await r.json()) as { lat?: unknown; lng?: unknown }
        const lat = Number(d.lat)
        const lng = Number(d.lng)
        if (
            Number.isFinite(lat) &&
            Number.isFinite(lng) &&
            lat >= -90 &&
            lat <= 90 &&
            lng >= -180 &&
            lng <= 180
        ) {
            return { lat, lng }
        }
    } catch {
        /* ignore */
    }
    return null
}

/**
 * Builds GET /jobs `location_or` (comma-separated) when the user names multiple metros.
 * API matches jobs whose location string contains ANY term — one request covers SF + NYC.
 */
function deriveLocationOrForJobsParams(
    args: Record<string, unknown>
): string | null {
    const explicit =
        typeof args.location_or === "string" ? args.location_or.trim() : ""
    if (explicit) {
        return explicit
            .split(",")
            .map((t) => t.trim())
            .filter(Boolean)
            .slice(0, 12)
            .join(",")
    }

    const loc = typeof args.location === "string" ? args.location.trim() : ""
    if (!loc) return null

    const parts = loc
        .split(/\s+or\s+/i)
        .flatMap((segment) => segment.split(/[,;/|]/))
        .map((p) => p.trim())
        .filter(Boolean)

    if (parts.length < 2) return null

    const seen = new Set<string>()
    const out: string[] = []
    for (const p of parts) {
        const k = p.toLowerCase()
        if (seen.has(k)) continue
        seen.add(k)
        out.push(p)
        if (out.length >= 12) break
    }
    return out.length >= 2 ? out.join(",") : null
}

function ipGeoFromLocationInfo(
    locationInfo: LocationInfo | null
): { lat: number; lng: number } | null {
    if (
        locationInfo?.lat != null &&
        locationInfo?.lng != null &&
        typeof locationInfo.lat === "number" &&
        typeof locationInfo.lng === "number" &&
        !Number.isNaN(locationInfo.lat) &&
        !Number.isNaN(locationInfo.lng)
    ) {
        return { lat: locationInfo.lat, lng: locationInfo.lng }
    }
    return null
}

type JobSearchGeoRefs = {
    jobsProxyGeoRef: React.MutableRefObject<{ lat: number; lng: number } | null>
}

/**
 * Prefer GET /jobs distance search (near_lat, near_lng, radius_km) over the `location`
 * substring filter so results cover a metro area and match the map.
 *
 * Chat never uses browser GPS or Photon — only GET /geo on the jobs proxy (server IP) and
 * client IP geolocation (`locationInfo`). Named places stay as `location` text on the API.
 * If the model already passed near_lat/near_lng, drop `location` to avoid conflicting filters.
 */
async function applySearchJobsGeoResolution(
    params: URLSearchParams,
    args: Record<string, unknown>,
    lastUserMessage: string,
    ipGeo: { lat: number; lng: number } | null,
    geoRefs: JobSearchGeoRefs,
    jobsApiUrl: string | null | undefined
): Promise<void> {
    const nearLatP = params.get("near_lat")
    const nearLngP = params.get("near_lng")
    const hasNearInParams =
        nearLatP != null &&
        nearLngP != null &&
        !Number.isNaN(parseFloat(nearLatP)) &&
        !Number.isNaN(parseFloat(nearLngP))

    if (hasNearInParams) {
        params.delete("location")
        if (!params.has("radius_km")) params.set("radius_km", "50")
        if (!params.has("exclude_remote")) params.set("exclude_remote", "true")
        return
    }

    if (params.has("location_or")) {
        params.delete("location")
        // Distance search ignores location_or on the server — drop geo so GET /jobs uses the OR filter.
        params.delete("near_lat")
        params.delete("near_lng")
        params.delete("radius_km")
        return
    }

    const userWantsNear =
        NEAR_ME_USER_MESSAGE_RE.test(lastUserMessage) ||
        locationArgImpliesNearMe(args, params)

    if (userWantsNear) {
        let jobsGeo = geoRefs.jobsProxyGeoRef.current
        if (!jobsGeo && jobsApiUrl) {
            const fresh = await fetchJobsProxyGeoCoords(jobsApiUrl)
            if (fresh) {
                geoRefs.jobsProxyGeoRef.current = fresh
                jobsGeo = fresh
            }
        }
        const best = jobsGeo ?? ipGeo ?? null
        if (best) {
            params.delete("location")
            params.set("near_lat", String(best.lat))
            params.set("near_lng", String(best.lng))
            if (!params.has("radius_km"))
                params.set("radius_km", SEARCH_JOBS_NEAR_ME_RADIUS_KM)
            if (!params.has("exclude_remote"))
                params.set("exclude_remote", "true")
        } else {
            params.delete("location")
        }
        return
    }

    // Named places: leave `location` on the query for API substring match (no Photon / no coords).
}

interface FileAttachmentProps {
    name: string
    type: string
    url?: string
    onRemove?: () => void
    themeColors: typeof darkColors
}

const FileAttachment = React.memo(function FileAttachment({
    name,
    type,
    url,
    onRemove,
    themeColors,
}: FileAttachmentProps) {
    const handleDownload = (e: React.MouseEvent) => {
        if (!url || onRemove) return
        e.stopPropagation()
        const link = document.createElement("a")
        link.href = url
        link.download = name || "download"
        document.body.appendChild(link)
        link.click()
        document.body.removeChild(link)
    }

    const fileLabel = React.useMemo(() => {
        if (name) {
            const ext = name.split(".").pop()
            if (ext && ext !== name) return ext.toUpperCase()
        }
        if (type) {
            if (type.includes("pdf")) return "PDF"
            if (type.includes("word") || type.includes("document")) return "DOC"
            if (type.includes("sheet") || type.includes("excel")) return "XLS"
            if (type.includes("presentation")) return "PPT"
            return type.split("/").pop()?.toUpperCase() || "FILE"
        }
        return "FILE"
    }, [name, type])

    return (
        <div
            data-layer="uploaded file"
            className="UploadedFile"
            onClick={handleDownload}
            style={{
                width: 86,
                height: 86,
                flexShrink: 0,
                padding: 8,
                position: "relative",
                background: onRemove
                    ? themeColors.background
                    : themeColors.surface,
                border:
                    themeColors.background === lightColors.background
                        ? `0.33px solid ${themeColors.border.subtle}`
                        : "none",
                overflow: "hidden",
                borderRadius: 16,
                flexDirection: "column",
                justifyContent: "space-between",
                alignItems: "flex-start",
                display: "inline-flex",
                cursor: url && !onRemove ? "pointer" : "default",
            }}
        >
            {onRemove && (
                <div
                    data-svg-wrapper
                    data-layer="remove button"
                    className="RemoveButton"
                    onClick={(e) => {
                        e.stopPropagation()
                        onRemove()
                    }}
                    style={{
                        right: 6,
                        top: 6,
                        position: "absolute",
                        cursor: "pointer",
                        zIndex: 10,
                    }}
                >
                    <svg
                        width="16"
                        height="16"
                        viewBox="0 0 16 16"
                        fill="none"
                        xmlns="http://www.w3.org/2000/svg"
                    >
                        <rect
                            width="16"
                            height="16"
                            rx="8"
                            fill={themeColors.surfaceHighlight}
                        />
                        <path
                            d="M11 5L5 11M5 5L11 11"
                            stroke={themeColors.text.primary}
                            strokeOpacity="0.95"
                            strokeWidth="1.2"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    </svg>
                </div>
            )}
            <div
                data-layer="file type"
                className="FileType"
                style={{
                    display: "flex",
                    flexDirection: "column",
                    color: themeColors.text.secondary,
                    fontSize: 12,
                    fontFamily: "Inter",
                    fontWeight: "400",
                    lineHeight: "18px",
                    wordWrap: "break-word",
                    flexShrink: 0,
                }}
            >
                {fileLabel}
            </div>
            <div
                data-layer="file name"
                className="FileName"
                style={{
                    display: "-webkit-box",
                    WebkitLineClamp: 2,
                    WebkitBoxOrient: "vertical",
                    color: themeColors.text.primary,
                    fontSize: 14,
                    fontFamily: "Inter",
                    fontWeight: "400",
                    lineHeight: "18px",
                    wordWrap: "break-word",
                    overflow: "hidden",
                    textOverflow: "ellipsis",
                    width: "100%",
                    flexShrink: 0,
                }}
            >
                {name}
            </div>
        </div>
    )
})

