const ORB_BASE_WIDTH = 100
const ORB_BASE_HEIGHT = 102

const GeminiLiveCharacter = ({
    isThinking,
    isSpeaking,
}: {
    isThinking: boolean
    isSpeaking: boolean
}) => {
    const [currentState, setCurrentState] = React.useState(
        GEMINI_EYE_STATES.LOOKING
    )
    const containerRef = React.useRef<HTMLDivElement>(null)
    const [scale, setScale] = React.useState(1.28)

    React.useEffect(() => {
        const el = containerRef.current
        if (!el) return
        const updateScale = () => {
            const { width, height } = el.getBoundingClientRect()
            const padding = 24
            const availW = Math.max(0, width - padding)
            const availH = Math.max(0, height - padding)
            const scaleW = availW / ORB_BASE_WIDTH
            const scaleH = availH / ORB_BASE_HEIGHT
            setScale(Math.min(scaleW, scaleH, 2))
        }
        updateScale()
        const observer = new ResizeObserver(updateScale)
        observer.observe(el)
        return () => observer.disconnect()
    }, [])

    React.useEffect(() => {
        let timeoutId: any

        if (isSpeaking) {
            // Loop between TALKING and BLINKING_TALKING
            const blinkLoop = () => {
                setCurrentState(GEMINI_EYE_STATES.TALKING)
                // Blink every 2-4 seconds randomly
                const nextBlink = 2000 + Math.random() * 2000
                timeoutId = setTimeout(() => {
                    setCurrentState(GEMINI_EYE_STATES.BLINKING_TALKING)
                    timeoutId = setTimeout(() => {
                        blinkLoop()
                    }, 150) // Blink duration
                }, nextBlink)
            }
            blinkLoop()
            return () => clearTimeout(timeoutId)
        }

        if (isThinking) {
            setCurrentState(GEMINI_EYE_STATES.THINKING)
            return
        }

        // Default: Waiting / Looking (Loop between LOOKING and BLINKING_LOOKING)
        const blinkLoopLooking = () => {
            setCurrentState(GEMINI_EYE_STATES.LOOKING)
            // Blink every 3-5 seconds randomly (slower blinking when idle)
            const nextBlink = 3000 + Math.random() * 2000
            timeoutId = setTimeout(() => {
                setCurrentState(GEMINI_EYE_STATES.BLINKING_LOOKING)
                timeoutId = setTimeout(() => {
                    blinkLoopLooking()
                }, 150)
            }, nextBlink)
        }
        blinkLoopLooking()
        return () => clearTimeout(timeoutId)
    }, [isThinking, isSpeaking])

    return (
        <div
            ref={containerRef}
            style={{
                width: "100%",
                height: "100%",
                minHeight: 0,
                alignSelf: "stretch",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                padding: 12,
                boxSizing: "border-box",
            }}
        >
            <div
                style={{
                    transform: `scale(${scale})`,
                    transformOrigin: "center center",
                    position: "relative",
                    width: ORB_BASE_WIDTH,
                    height: ORB_BASE_HEIGHT,
                }}
            >
                <div
                    style={{
                        width: 100,
                        height: 102,
                        position: "relative",
                        cursor: "pointer",
                        transition: "transform 0.3s",
                        boxShadow: "0px 4px 12px hsla(0, 0%, 0%, 0.08)", // Hardcoded shadow for animated character
                        borderRadius: 9999,
                    }}
                >
                    {/* Layer: White Body */}
                    <div
                        style={{
                            position: "absolute",
                            left: 0,
                            top: 0,
                            width: 100,
                            height: 102,
                            background: "#FFFFFF", // Hardcoded white for animated character
                            borderRadius: 9999,
                        }}
                    />

                    {/* Layer: Blue Blur */}
                    <div
                        style={{
                            position: "absolute",
                            width: 76.66,
                            height: 80,
                            left: 11.66,
                            top: 10.31,
                            background:
                                "linear-gradient(180deg, hsl(200, 100%, 50%) 0%, hsla(0, 0%, 100%, 0) 100%)", // Hardcoded colors for animated character
                            boxShadow:
                                "0px 16px 24px hsla(200, 100%, 50%, 0.25)", // Hardcoded shadow for animated character
                            borderRadius: 9999,
                            filter: "blur(8px)",
                        }}
                    />

                    {/* Layer: Eyes */}
                    <GeminiEye config={currentState.eye1} id="eye1" />
                    <GeminiEye config={currentState.eye2} id="eye2" />
                </div>
            </div>
        </div>
    )
}

// --- HELPER COMPONENT: VIDEO PLAYER ---
const VideoPlayer = React.memo(function VideoPlayer({
    stream,
    isMirrored = false,
    style = {},
    muted = false,
    onVideoSize,
    placeholder,
    themeColors = darkColors,
    objectFit = "cover",
}: {
    stream: MediaStream | null
    isMirrored?: boolean
    style?: React.CSSProperties
    muted?: boolean
    onVideoSize?: (width: number, height: number) => void
    placeholder?: string
    themeColors?: typeof darkColors
    objectFit?: "contain" | "cover" | "fill" | "none" | "scale-down"
}) {
    const videoRef = React.useRef<HTMLVideoElement>(null)

    React.useEffect(() => {
        if (videoRef.current && stream) {
            videoRef.current.srcObject = stream
        } else if (videoRef.current) {
            videoRef.current.srcObject = null
        }
    }, [stream])

    // Monitor video dimensions
    React.useEffect(() => {
        const video = videoRef.current
        if (!video || !onVideoSize) return

        const handleResize = () => {
            if (video.videoWidth && video.videoHeight) {
                onVideoSize(video.videoWidth, video.videoHeight)
            }
        }

        video.addEventListener("loadedmetadata", handleResize)
        video.addEventListener("resize", handleResize)

        // Polling in case resize event doesn't fire on stream changes
        const interval = setInterval(handleResize, 1000)

        return () => {
            video.removeEventListener("loadedmetadata", handleResize)
            video.removeEventListener("resize", handleResize)
            clearInterval(interval)
        }
    }, [stream, onVideoSize])

    // Use theme surface color for placeholder background, black for video (always dark for video tiles)
    const containerBackground =
        !stream && placeholder ? themeColors.surface : darkColors.surfaceBlack
    const placeholderTextColor = "${themeColors.text.tertiary}"

    return (
        <div
            style={{
                width: "100%",
                height: "100%",
                background: containerBackground,
                position: "relative",
                ...style,
            }}
        >
            <video
                ref={videoRef}
                autoPlay
                playsInline
                muted={muted}
                style={{
                    width: "100%",
                    height: "100%",
                    objectFit: objectFit,
                    transform: isMirrored ? "scaleX(-1)" : "none",
                    display: stream ? "block" : "none",
                }}
            />
            {!stream && placeholder && (
                <div
                    style={{
                        position: "absolute",
                        top: 0,
                        left: 0,
                        width: "100%",
                        height: "100%",
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        color: placeholderTextColor,
                        fontSize: 14,
                        padding: 8,
                        textAlign: "center",
                    }}
                >
                    {placeholder}
                </div>
            )}
        </div>
    )
})

// --- HELPER COMPONENT: DOC EDITOR ---

/** Block-level typography for Docs (editor toolbar + exports). Inter only. */
/** Title and Heading 1 both use `<h1>`; Heading 1 is `h1.doc-block-section` (replaces `<h2>`). */
type DocBlockKey = "p" | "section" | "title"

const DOC_FONT_STACK = "Inter, system-ui, sans-serif"
const DOC_BLOCK_SECTION_CLASS = "doc-block-section"
const DOC_BLOCK_TITLE_CLASS = "doc-block-title"

const DOC_BLOCK_OPTIONS: readonly {
    key: DocBlockKey
    label: string
    /** Rendered size in the document and in PDF/DOCX export. */
    fontSizePx: number
    /** If set, block-style dropdown row uses this (e.g. Paragraph preview 14px while doc body stays 16px). */
    dropdownFontSizePx?: number
    fontWeight: number
    rowMinHeightPx: number
}[] = [
    {
        key: "title",
        label: "Title",
        fontSizePx: 28,
        fontWeight: 700,
        rowMinHeightPx: 48,
    },
    {
        key: "section",
        label: "Heading 1",
        fontSizePx: 18,
        fontWeight: 700,
        rowMinHeightPx: 40,
    },
    {
        key: "p",
        label: "Paragraph",
        fontSizePx: 16,
        dropdownFontSizePx: 14,
        fontWeight: 400,
        rowMinHeightPx: 40,
    },
] as const

function docBlockExportSizePx(key: DocBlockKey): number {
    const o = DOC_BLOCK_OPTIONS.find((b) => b.key === key)
    return o?.fontSizePx ?? 16
}

/**
 * One-page ATS-style PDF from resume/cover HTML (same pipeline as DocEditor PDF export).
 */
async function docHtmlToOnePagePdfBytes(
    htmlFragment: string,
    isCoverLetter: boolean
): Promise<Uint8Array> {

                        // ATS-safe text-based PDF: selectable text, Standard Type 1 fonts (no embedding needed).
                        const PAGE_W_PT = 612
                        const PAGE_H_PT = 792
                        const MARGIN_PT = 36
                        const CONTENT_W_PT = PAGE_W_PT - MARGIN_PT * 2
                        const CONTENT_H_PT = PAGE_H_PT - MARGIN_PT * 2
                        const DOC_PX_BODY = docBlockExportSizePx("p")
                        const DOC_PX_TITLE = docBlockExportSizePx("title")
                        const DOC_PX_SECTION = docBlockExportSizePx("section")

                        // Spacing constants — cover letter gets slightly more air.
                        const bodyLineMult = isCoverLetter ? 1.46 : 1.45
                        const gapAfterParagraph = (pt: number) => pt * 0.2
                        const gapAfterListItem = (pt: number) =>
                            isCoverLetter ? pt * 0.35 : pt * 0.15
                        // Small gap before the first bullet of each list / nested list.
                        const listFirstBulletGap = (pt: number) =>
                            isCoverLetter ? pt * 0.32 : 0

                        // --- Parse HTML → flat block list ---
                        type Run = {
                            text: string
                            bold: boolean
                            italic: boolean
                        }
                        type Block =
                            | { kind: "h1"; text: string }
                            | { kind: "h2"; text: string }
                            | { kind: "p"; runs: Run[] }
                            | { kind: "li"; runs: Run[]; indent: number }
                            | { kind: "rule" }

                        const parseHTML = (): Block[] => {
                            const tmp = document.createElement("div")
                            tmp.innerHTML = htmlFragment
                            const out: Block[] = []

                            // Collect inline text runs, stopping at nested list children.
                            const inlineRuns = (
                                el: Element,
                                b = false,
                                i = false
                            ): Run[] => {
                                const runs: Run[] = []
                                const walk = (
                                    node: Node,
                                    b: boolean,
                                    i: boolean
                                ) => {
                                    if (node.nodeType === Node.TEXT_NODE) {
                                        const t = node.textContent || ""
                                        if (t)
                                            runs.push({
                                                text: t,
                                                bold: b,
                                                italic: i,
                                            })
                                    } else if (
                                        node.nodeType === Node.ELEMENT_NODE
                                    ) {
                                        const tag = (
                                            node as Element
                                        ).tagName.toLowerCase()
                                        if (tag === "ul" || tag === "ol") return
                                        const nb =
                                            b || tag === "b" || tag === "strong"
                                        const ni =
                                            i || tag === "i" || tag === "em"
                                        node.childNodes.forEach((c) =>
                                            walk(c, nb, ni)
                                        )
                                    }
                                }
                                // Walk children, not el itself (b/i already passed in)
                                el.childNodes.forEach((c) => walk(c, b, i))
                                return runs
                            }

                            const processLi = (
                                liEl: Element,
                                indent: number
                            ) => {
                                const runs = inlineRuns(liEl)
                                if (runs.some((r) => r.text.trim()))
                                    out.push({ kind: "li", runs, indent })
                                liEl.childNodes.forEach((child) => {
                                    if (child.nodeType === Node.ELEMENT_NODE) {
                                        const tag = (
                                            child as Element
                                        ).tagName.toLowerCase()
                                        if (tag === "ul" || tag === "ol")
                                            processNode(child, indent + 1)
                                    }
                                })
                            }

                            const processNode = (
                                node: Node,
                                listIndent = 0
                            ) => {
                                if (node.nodeType !== Node.ELEMENT_NODE) return
                                const el = node as Element
                                const tag = el.tagName.toLowerCase()
                                if (tag === "h1") {
                                    if (
                                        el.classList.contains(
                                            DOC_BLOCK_SECTION_CLASS
                                        )
                                    ) {
                                        out.push({ kind: "rule" })
                                        out.push({
                                            kind: "h2",
                                            text:
                                                el.textContent?.trim() || "",
                                        })
                                    } else {
                                        out.push({
                                            kind: "h1",
                                            text:
                                                el.textContent?.trim() || "",
                                        })
                                    }
                                } else if (tag === "h2") {
                                    out.push({ kind: "rule" })
                                    out.push({
                                        kind: "h2",
                                        text: el.textContent?.trim() || "",
                                    })
                                } else if (tag === "h3" || tag === "h4") {
                                    const runs = inlineRuns(el)
                                    if (runs.some((r) => r.text.trim()))
                                        out.push({ kind: "p", runs })
                                } else if (tag === "p") {
                                    const runs = inlineRuns(el)
                                    if (runs.some((r) => r.text.trim()))
                                        out.push({ kind: "p", runs })
                                } else if (tag === "ul" || tag === "ol") {
                                    el.childNodes.forEach((child) => {
                                        if (
                                            (
                                                child as Element
                                            ).tagName?.toLowerCase() === "li"
                                        )
                                            processLi(
                                                child as Element,
                                                listIndent
                                            )
                                    })
                                } else if (tag === "li") {
                                    processLi(el, listIndent)
                                } else if (tag !== "br") {
                                    el.childNodes.forEach((c) =>
                                        processNode(c, listIndent)
                                    )
                                }
                            }

                            tmp.childNodes.forEach((c) => processNode(c))
                            return out
                        }

                        const blocks = parseHTML()

                        // --- Load pdf-lib and embed fonts ---
                        const { PDFDocument, rgb, StandardFonts } =
                            await import("https://esm.sh/pdf-lib@1.17.1")

                        const pdfDoc = await PDFDocument.create()
                        const page = pdfDoc.addPage([PAGE_W_PT, PAGE_H_PT])

                        const [helReg, helBold, helItalic, helBoldIt] =
                            await Promise.all([
                                pdfDoc.embedFont(StandardFonts.Helvetica),
                                pdfDoc.embedFont(StandardFonts.HelveticaBold),
                                pdfDoc.embedFont(StandardFonts.HelveticaOblique),
                                pdfDoc.embedFont(
                                    StandardFonts.HelveticaBoldOblique
                                ),
                            ])

                        const black = rgb(0.07, 0.07, 0.07)
                        const gray = rgb(0.2, 0.2, 0.2)

                        // Sanitize to WinAnsi-safe characters (Standard Type 1 fonts use Latin-1 encoding).
                        const sanitize = (s: string) =>
                            s
                                .replace(/[\u2018\u2019]/g, "'")
                                .replace(/[\u201C\u201D]/g, '"')
                                .replace(/[\u2013\u2014]/g, "-")
                                .replace(/[\u2022\u25CF]/g, "*")
                                .replace(/\u25E6/g, "-")
                                .replace(/\u2026/g, "...")
                                .replace(/[^\x20-\x7E\xA0-\xFF]/g, "")

                        const pickFont = (bold: boolean, italic: boolean) =>
                            bold && italic
                                ? helBoldIt
                                : bold
                                  ? helBold
                                  : italic
                                    ? helItalic
                                    : helReg

                        // Word-wrap styled runs using real font metrics. Returns lines of runs.
                        const wrapRuns = (
                            runs: Run[],
                            maxW: number,
                            fontSize: number
                        ): Run[][] => {
                            type Word = Run & { space: boolean }
                            const words: Word[] = []
                            for (const run of runs) {
                                const parts = sanitize(run.text).split(/(\s+)/)
                                for (const p of parts) {
                                    if (!p) continue
                                    if (/^\s+$/.test(p)) {
                                        if (words.length)
                                            words[words.length - 1].space = true
                                    } else {
                                        words.push({
                                            text: p,
                                            bold: run.bold,
                                            italic: run.italic,
                                            space: false,
                                        })
                                    }
                                }
                            }

                            const lines: Run[][] = []
                            let curLine: Word[] = []
                            let curW = 0

                            const flush = () => {
                                if (!curLine.length) return
                                const lineRuns: Run[] = []
                                curLine.forEach((w, wi) => {
                                    const needSpace = wi > 0
                                    const last = lineRuns[lineRuns.length - 1]
                                    if (
                                        last &&
                                        last.bold === w.bold &&
                                        last.italic === w.italic
                                    ) {
                                        last.text +=
                                            (needSpace ? " " : "") + w.text
                                    } else {
                                        lineRuns.push({
                                            text:
                                                (needSpace && last ? " " : "") +
                                                w.text,
                                            bold: w.bold,
                                            italic: w.italic,
                                        })
                                    }
                                })
                                lines.push(lineRuns)
                                curLine = []
                                curW = 0
                            }

                            for (const word of words) {
                                const f = pickFont(word.bold, word.italic)
                                const spW = f.widthOfTextAtSize(" ", fontSize)
                                const wW = f.widthOfTextAtSize(
                                    word.text,
                                    fontSize
                                )
                                const addW = curLine.length ? spW + wW : wW
                                if (curLine.length && curW + addW > maxW) {
                                    flush()
                                    curLine = [word]
                                    curW = wW
                                } else {
                                    curLine.push(word)
                                    curW += addW
                                }
                            }
                            flush()
                            return lines.length
                                ? lines
                                : [[{ text: "", bold: false, italic: false }]]
                        }

                        // Draw a line of styled runs, returning the x position after the last character.
                        const drawRuns = (
                            runs: Run[],
                            x: number,
                            y: number,
                            fontSize: number,
                            color: typeof black
                        ) => {
                            let cx = x
                            for (const run of runs) {
                                const t = sanitize(run.text)
                                if (!t) continue
                                const f = pickFont(run.bold, run.italic)
                                page.drawText(t, {
                                    x: cx,
                                    y,
                                    font: f,
                                    size: fontSize,
                                    color,
                                })
                                cx += f.widthOfTextAtSize(t, fontSize)
                            }
                            return cx
                        }

                        // Measure total layout height at a given base font size using real font metrics.
                        // This is the same logic as the draw pass, just without the draw calls.
                        const measureHeight = (basePt: number): number => {
                            const px = (n: number) =>
                                basePt * (n / DOC_PX_BODY)
                            const h1Pt = px(DOC_PX_TITLE)
                            const h2Pt = px(DOC_PX_SECTION)
                            const lineH = basePt * bodyLineMult
                            const h1LineH = h1Pt * 1.3
                            const h2LineH = h2Pt * 1.35
                            let totalH = 0
                            let firstP = true
                            let prev: Block | null = null
                            for (const block of blocks) {
                                if (block.kind === "h1") {
                                    totalH +=
                                        wrapRuns(
                                            [
                                                {
                                                    text: block.text,
                                                    bold: true,
                                                    italic: false,
                                                },
                                            ],
                                            CONTENT_W_PT,
                                            h1Pt
                                        ).length *
                                            h1LineH +
                                        basePt * 0.4
                                } else if (block.kind === "rule") {
                                    totalH += basePt * 0.5
                                } else if (block.kind === "h2") {
                                    totalH +=
                                        wrapRuns(
                                            [
                                                {
                                                    text: block.text,
                                                    bold: true,
                                                    italic: false,
                                                },
                                            ],
                                            CONTENT_W_PT,
                                            h2Pt
                                        ).length *
                                            h2LineH +
                                        basePt * 0.8
                                } else if (block.kind === "p") {
                                    if (isCoverLetter && !firstP)
                                        totalH += basePt * bodyLineMult
                                    totalH +=
                                        wrapRuns(
                                            block.runs,
                                            CONTENT_W_PT,
                                            basePt
                                        ).length *
                                            lineH +
                                        gapAfterParagraph(basePt)
                                    firstP = false
                                } else if (block.kind === "li") {
                                    const newList =
                                        prev == null ||
                                        prev.kind !== "li" ||
                                        block.indent >
                                            (prev as { indent: number }).indent
                                    if (isCoverLetter && newList)
                                        totalH += listFirstBulletGap(basePt)
                                    const bulletW =
                                        basePt * 1.4 * (block.indent + 1)
                                    totalH +=
                                        wrapRuns(
                                            block.runs,
                                            CONTENT_W_PT - bulletW,
                                            basePt
                                        ).length *
                                            lineH +
                                        gapAfterListItem(basePt)
                                }
                                prev = block
                            }
                            return totalH
                        }

                        // Binary-search for the largest body pt that fits on one page (headings scale with DOC_BLOCK_OPTIONS px).
                        let lo = 6,
                            hi = 20,
                            bestPt = 10
                        for (let i = 0; i < 12; i++) {
                            const mid = (lo + hi) / 2
                            if (measureHeight(mid) <= CONTENT_H_PT) {
                                bestPt = mid
                                lo = mid
                            } else hi = mid
                        }

                        const px = (n: number) => bestPt * (n / DOC_PX_BODY)
                        const h1Pt = px(DOC_PX_TITLE)
                        const h2Pt = px(DOC_PX_SECTION)
                        const baseBodyLineH = bestPt * bodyLineMult
                        const h1LineH = h1Pt * 1.3
                        const h2LineH = h2Pt * 1.35

                        // Draw all blocks onto the page.
                        let y = PAGE_H_PT - MARGIN_PT
                        let firstP = true
                        let prev: Block | null = null
                        for (const block of blocks) {
                            if (block.kind === "h1") {
                                for (const line of wrapRuns(
                                    [
                                        {
                                            text: sanitize(block.text),
                                            bold: true,
                                            italic: false,
                                        },
                                    ],
                                    CONTENT_W_PT,
                                    h1Pt
                                )) {
                                    y -= h1LineH
                                    drawRuns(
                                        line,
                                        MARGIN_PT,
                                        y,
                                        h1Pt,
                                        black
                                    )
                                }
                                y -= bestPt * 0.4
                            } else if (block.kind === "rule") {
                                y -= bestPt * 0.5
                            } else if (block.kind === "h2") {
                                page.drawLine({
                                    start: {
                                        x: MARGIN_PT,
                                        y: y - bestPt * 0.2,
                                    },
                                    end: {
                                        x: PAGE_W_PT - MARGIN_PT,
                                        y: y - bestPt * 0.2,
                                    },
                                    thickness: 0.5,
                                    color: gray,
                                })
                                for (const line of wrapRuns(
                                    [
                                        {
                                            text: sanitize(block.text),
                                            bold: true,
                                            italic: false,
                                        },
                                    ],
                                    CONTENT_W_PT,
                                    h2Pt
                                )) {
                                    y -= h2LineH
                                    drawRuns(
                                        line,
                                        MARGIN_PT,
                                        y,
                                        h2Pt,
                                        black
                                    )
                                }
                                y -= bestPt * 0.5
                            } else if (block.kind === "p") {
                                if (isCoverLetter && !firstP)
                                    y -= bestPt * bodyLineMult
                                for (const line of wrapRuns(
                                    block.runs,
                                    CONTENT_W_PT,
                                    bestPt
                                )) {
                                    y -= baseBodyLineH
                                    drawRuns(
                                        line,
                                        MARGIN_PT,
                                        y,
                                        bestPt,
                                        black
                                    )
                                }
                                y -= gapAfterParagraph(bestPt)
                                firstP = false
                            } else if (block.kind === "li") {
                                const newList =
                                    prev == null ||
                                    prev.kind !== "li" ||
                                    block.indent >
                                        (prev as { indent: number }).indent
                                if (isCoverLetter && newList)
                                    y -= listFirstBulletGap(bestPt)
                                const bulletIndent =
                                    bestPt * 1.4 * (block.indent + 1)
                                let isFirst = true
                                for (const line of wrapRuns(
                                    block.runs,
                                    CONTENT_W_PT - bulletIndent,
                                    bestPt
                                )) {
                                    y -= baseBodyLineH
                                    if (isFirst) {
                                        const r =
                                            block.indent === 0
                                                ? bestPt * 0.11
                                                : bestPt * 0.085
                                        page.drawCircle({
                                            x:
                                                MARGIN_PT +
                                                bulletIndent -
                                                bestPt * 0.52,
                                            y: y + bestPt * 0.32,
                                            size: r,
                                            color: black,
                                        })
                                        isFirst = false
                                    }
                                    drawRuns(
                                        line,
                                        MARGIN_PT + bulletIndent,
                                        y,
                                        bestPt,
                                        black
                                    )
                                }
                                y -= gapAfterListItem(bestPt)
                            }
                            prev = block
                        }

                        return await pdfDoc.save()
}

function applyDocBlockClasses(el: HTMLElement, blockKey: DocBlockKey) {
    if (blockKey === "p") {
        el.classList.remove(DOC_BLOCK_TITLE_CLASS, DOC_BLOCK_SECTION_CLASS)
        return
    }
    if (blockKey === "title") {
        el.classList.remove(DOC_BLOCK_SECTION_CLASS)
        el.classList.add(DOC_BLOCK_TITLE_CLASS)
        return
    }
    if (blockKey === "section") {
        el.classList.remove(DOC_BLOCK_TITLE_CLASS)
        el.classList.add(DOC_BLOCK_SECTION_CLASS)
    }
}

interface DocEditorProps {
    content: string
    onChange: (content: string) => void
    themeColors?: typeof darkColors
    isMobileLayout?: boolean
    remoteCursors?: Map<string, { x: number; y: number; color: string }>
    onCursorMove?: (x: number, y: number) => void
    docType?: "doc" | "resume" | "cover_letter"
    onClose?: () => void
    hideLeftToolbar?: boolean
    hideContent?: boolean
    docCompany?: string
    /** Profile name (`you_name`). Resume prefers this over the doc first line; cover letter uses it when set. */
    userDisplayName?: string
}

const ToolbarButton = React.memo(
    ({
        id,
        icon,
        onClick,
        tooltip,
        isActive = false,
        isHovered,
        onHoverChange,
        themeColors,
    }: {
        id: string
        icon: React.ReactNode
        onClick: (e: React.MouseEvent) => void
        tooltip: string
        isActive?: boolean
        isHovered: boolean
        onHoverChange: (isHovered: boolean) => void
        themeColors: any
    }) => (
        <button
            className={id}
            onMouseDown={(e) => e.preventDefault()}
            onPointerDown={(e) => e.preventDefault()}
            onClick={(e) => {
                haptic.light()
                onHoverChange(false)
                onClick(e)
            }}
            onMouseEnter={() => onHoverChange(true)}
            onMouseLeave={() => onHoverChange(false)}
            style={{
                width: 40,
                height: 40,
                background: isActive
                    ? themeColors.hover.default
                    : "transparent",
                borderRadius: 28,
                justifyContent: "center",
                alignItems: "center",
                display: "flex",
                cursor: "pointer",
                position: "relative",
                border: "none",
                outline: "none",
                padding: 0,
            }}
            type="button"
            aria-label={tooltip}
            aria-pressed={isActive}
        >
            {icon}
            {isHovered && (
                <Tooltip
                    style={{
                        top: "100%",
                        left: "50%",
                        transform: "translate(-50%, 8px)",
                        zIndex: 100,
                    }}
                >
                    {tooltip}
                </Tooltip>
            )}
        </button>
    )
)

// --- P2P Helper Functions ---
function getCaretCharacterOffsetWithin(element: HTMLElement): number {
    let caretOffset = 0
    const doc = element.ownerDocument || document
    const win = doc.defaultView || window
    const sel = win.getSelection()
    if (sel && sel.rangeCount > 0) {
        const range = sel.getRangeAt(0)
        const preCaretRange = range.cloneRange()
        preCaretRange.selectNodeContents(element)
        preCaretRange.setEnd(range.endContainer, range.endOffset)
        caretOffset = preCaretRange.toString().length
    }
    return caretOffset
}

function setCaretPosition(element: HTMLElement, offset: number) {
    const createRange = (
        node: Node,
        chars: { count: number },
        range?: Range
    ): Range | undefined => {
        if (!range) {
            range = document.createRange()
            range.selectNode(node)
            range.setStart(node, 0)
        }

        if (chars.count === 0) {
            range.setEnd(node, chars.count)
        }

        if (node && chars.count > 0) {
            if (node.nodeType === Node.TEXT_NODE) {
                if (node.textContent && node.textContent.length < chars.count) {
                    chars.count -= node.textContent.length
                } else {
                    range.setEnd(node, chars.count)
                    chars.count = 0
                }
            } else {
                for (let lp = 0; lp < node.childNodes.length; lp++) {
                    range = createRange(node.childNodes[lp], chars, range)
                    if (chars.count === 0) {
                        break
                    }
                }
            }
        }
        return range
    }

    if (offset >= 0) {
        const selection = window.getSelection()
        const range = createRange(element, { count: offset })
        if (range) {
            range.collapse(false)
            selection?.removeAllRanges()
            selection?.addRange(range)
        }
    }
}

