// --- HELPER: DEBUG PANEL (shared chrome for P2P vs Tools & MCP) ---
function DebugPanel({
    title,
    position,
    logs,
    themeColors,
    meta,
    onClear,
}: {
    title: string
    position: "left" | "right"
    logs: string[]
    themeColors: typeof darkColors
    meta: React.ReactNode
    onClear: () => void
}) {
    const scrollRef = React.useRef<HTMLDivElement>(null)
    const [copied, setCopied] = React.useState(false)

    React.useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight
        }
    }, [logs])

    const handleCopy = () => {
        const logsText = logs.join("\n")
        navigator.clipboard
            .writeText(logsText)
            .then(() => {
                setCopied(true)
                setTimeout(() => setCopied(false), 2000)
            })
            .catch((err) => {
                console.error("Failed to copy logs:", err)
            })
    }

    const btnStyle: React.CSSProperties = {
        background: themeColors.semantic.accent,
        color: themeColors.text.primary,
        border: "none",
        borderRadius: 6,
        padding: "4px 8px",
        fontSize: 10,
        cursor: "pointer",
        fontWeight: "600",
        transition: "all 0.2s",
        flexShrink: 0,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        minWidth: 28,
        minHeight: 28,
    }

    return (
        <motion.div
            drag
            dragMomentum={false}
            dragElastic={0.1}
            style={{
                position: "fixed",
                bottom: 20,
                ...(position === "left" ? { left: 20 } : { right: 20 }),
                width: 380,
                height: 440,
                background: themeColors.surfaceHighlight,
                color: themeColors.text.secondary,
                fontFamily: "monospace",
                fontSize: 12,
                padding: 12,
                overflow: "hidden",
                zIndex: 9999,
                pointerEvents: "auto",
                borderRadius: 28,
                display: "flex",
                flexDirection: "column",
                cursor: "grab",
            }}
            whileDrag={{ cursor: "grabbing", scale: 1.01 }}
        >
            <div
                style={{
                    display: "flex",
                    flexDirection: "column",
                    gap: 6,
                    marginBottom: 8,
                    paddingBottom: 8,
                    flexShrink: 0,
                }}
            >
                {meta}
            </div>

            <div
                style={{
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center",
                    marginBottom: 6,
                    flexShrink: 0,
                    gap: 8,
                }}
            >
                <div
                    style={{
                        color: themeColors.text.primary,
                        fontWeight: "bold",
                        fontSize: 13,
                        minWidth: 0,
                    }}
                >
                    {title}
                </div>
                <div
                    style={{
                        display: "flex",
                        alignItems: "center",
                        gap: 6,
                        flexShrink: 0,
                    }}
                >
                    <button
                        type="button"
                        title="Clear log"
                        aria-label="Clear log"
                        onClick={(e) => {
                            e.stopPropagation()
                            onClear()
                        }}
                        style={btnStyle}
                    >
                        <svg
                            width="14"
                            height="14"
                            viewBox="0 0 24 24"
                            fill="none"
                            stroke="currentColor"
                            strokeWidth="2"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                            aria-hidden
                        >
                            <path d="M21 12a9 9 0 1 1-3-6.7L21 8" />
                            <path d="M21 3v5h-5" />
                        </svg>
                    </button>
                    <button
                        type="button"
                        onClick={(e) => {
                            e.stopPropagation()
                            handleCopy()
                        }}
                        style={{
                            ...btnStyle,
                            background: copied
                                ? themeColors.coloredAccents.rainbow[3]
                                : themeColors.semantic.accent,
                            minWidth: "auto",
                            padding: "4px 10px",
                        }}
                    >
                        {copied ? "✓ Copied" : "Copy"}
                    </button>
                </div>
            </div>

            <div
                ref={scrollRef}
                style={{
                    flex: 1,
                    overflowY: "auto",
                    fontSize: 11,
                    lineHeight: 1.3,
                }}
            >
                {logs.slice(-100).map((line, i) => (
                    <div
                        key={i}
                        style={{ marginBottom: 3, wordBreak: "break-word" }}
                    >
                        {line}
                    </div>
                ))}
            </div>
        </motion.div>
    )
}

// --- HELPER COMPONENT: REPORT MODAL ---
interface ReportModalProps {
    isOpen: boolean
    onClose: () => void
    onSubmit: (reason: string) => void
    participantCount?: number
    themeColors?: typeof darkColors
    reportType?: "user" | "chat"
}

function ReportModal({
    isOpen,
    onClose,
    onSubmit,
    participantCount = 2,
    themeColors = darkColors,
    reportType = "user",
}: ReportModalProps) {
    const [selected, setSelected] = React.useState<string | null>(null)
    const [hoveredRow, setHoveredRow] = React.useState<string | null>(null)
    const [isCloseHovered, setIsCloseHovered] = React.useState(false)

    const reasons = [
        "Violence & self-harm",
        "Sexual exploitation & abuse",
        "Child/teen exploitation",
        "Bullying & harassment",
        "Spam, fraud & deception",
        "Privacy violation",
        "Intellectual property",
        "Age-inappropriate content",
        "Something else",
    ]

    // Reset selected when modal opens/closes
    React.useEffect(() => {
        if (!isOpen) {
            setSelected(null)
        }
    }, [isOpen])

    const handleBackdropClick = (e: React.MouseEvent) => {
        if (e.target === e.currentTarget) onClose()
    }

    const isMobileLayout =
        typeof window !== "undefined" && window.innerWidth < 768
    const isMultiParty = participantCount > 2
    const title = reportType === "chat" ? "Report chat" : "Report user"
    const question =
        reportType === "chat"
            ? isMultiParty
                ? "Why are you reporting this chat? User in violation will be banned."
                : "Why are you reporting this chat?"
            : isMultiParty
              ? "Why are you reporting this user? User in violation will be banned."
              : "Why are you reporting this user?"

    if (!isOpen) return null

    return (
        <ModalSheet
            isOpen={isOpen}
            onClose={onClose}
            themeColors={themeColors}
            zIndex={10000}
            className="ReportOverlay"
            sheetStyle={{
                width: isMobileLayout ? "100%" : 400,
                height: isMobileLayout ? "calc(100% - 16px)" : "auto",
                maxWidth: isMobileLayout ? "none" : 400,
                maxHeight: isMobileLayout ? "none" : 600,
                paddingTop: 24,
                paddingBottom: 28,
                paddingLeft: isMobileLayout ? 16 : 28,
                paddingRight: isMobileLayout ? 16 : 28,
                boxShadow: "0px 4px 24px hsla(0, 0%, 0%, 0.04)",
                borderRadius: isMobileLayout ? "24px 24px 0 0" : 48,
                outline: `0.33px ${themeColors.hover.strong} solid`,
                outlineOffset: "-0.33px",
                justifyContent: "flex-start",
                alignItems: "flex-start",
                gap: 24,
            }}
        >
            {/* Header */}
            <div
                style={{
                    alignSelf: "stretch",
                    height: "auto",
                    position: "relative",
                    flexDirection: "column",
                    justifyContent: "center",
                    alignItems: "flex-start",
                    gap: 8,
                    display: "flex",
                }}
            >
                <div
                    style={{
                        alignSelf: "stretch",
                        color: themeColors.text.primary,
                        fontSize: 16,
                        fontFamily: "Inter",
                        fontWeight: "400",
                        lineHeight: "18px",
                        wordWrap: "break-word",
                    }}
                >
                    {title}
                </div>
                <div
                    style={{
                        alignSelf: "stretch",
                        justifyContent: "center",
                        display: "flex",
                        flexDirection: "column",
                        color: themeColors.text.secondary,
                        fontSize: 12,
                        fontFamily: "Inter",
                        fontWeight: "400",
                        lineHeight: "17px",
                        wordWrap: "break-word",
                    }}
                >
                    {question}
                </div>
                <div
                    data-svg-wrapper
                    data-layer="close report button"
                    className="CloseReportButtonHasAFillHoverEffect"
                    style={{
                        right: isMobileLayout ? 0 : -12,
                        top: -12,
                        position: "absolute",
                        cursor: "pointer",
                        width: 36,
                        height: 36,
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        background: isCloseHovered
                            ? themeColors.hover.strong
                            : "transparent",
                        borderRadius: "50%",
                        transition: "background 0.2s",
                    }}
                    onClick={onClose}
                    onMouseEnter={() =>
                        !isMobileLayout && setIsCloseHovered(true)
                    }
                    onMouseLeave={() => setIsCloseHovered(false)}
                >
                    <svg
                        width="36"
                        height="36"
                        viewBox="0 0 36 36"
                        fill="none"
                        xmlns="http://www.w3.org/2000/svg"
                    >
                        <path
                            d="M23.25 12.75L12.75 23.25M12.75 12.75L23.25 23.25"
                            stroke={themeColors.text.primary}
                            strokeOpacity="0.95"
                            strokeWidth="1.2"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    </svg>
                </div>
            </div>

            {/* Options List */}
            <div
                style={{
                    display: "flex",
                    flexDirection: "column",
                }}
            >
                {reasons.map((reason) => (
                    <div
                        key={reason}
                        onClick={() => setSelected(reason)}
                        onMouseEnter={() => setHoveredRow(reason)}
                        onMouseLeave={() => setHoveredRow(null)}
                        style={{
                            display: "flex",
                            alignItems: "center",
                            gap: 8,
                            padding: "8px 0",
                            cursor: "pointer",
                        }}
                    >
                        <div
                            style={{
                                width: 16,
                                height: 16,
                                borderRadius: "50%",
                                border: `0.33px solid ${selected === reason ? themeColors.text.primary : themeColors.text.secondary}`,
                                background:
                                    hoveredRow === reason
                                        ? themeColors.border.subtle
                                        : "transparent",
                                display: "flex",
                                alignItems: "center",
                                justifyContent: "center",
                                boxSizing: "border-box",
                            }}
                        >
                            {selected === reason && (
                                <div
                                    style={{
                                        width: 7,
                                        height: 7,
                                        borderRadius: "50%",
                                        background: themeColors.text.primary,
                                    }}
                                />
                            )}
                        </div>
                        <div
                            style={{
                                color: themeColors.text.primary,
                                fontSize: 15,
                                fontFamily: "Inter",
                                fontWeight: "400",
                                opacity: 0.95,
                            }}
                        >
                            {reason}
                        </div>
                    </div>
                ))}
            </div>

            {/* Footer / Submit */}
            <div
                style={{
                    display: "flex",
                    justifyContent: "flex-end",
                }}
            >
                <button
                    disabled={!selected}
                    onClick={() => selected && onSubmit(selected)}
                    style={{
                        padding: "10px 12px",
                        borderRadius: 28,
                        background: selected
                            ? themeColors.text.primary
                            : themeColors.surface,
                        color: selected
                            ? themeColors.surfaceBlack
                            : themeColors.text.tertiary,
                        border: "none",
                        fontSize: 14,
                        fontFamily: "Inter",
                        fontWeight: "500",
                        cursor: selected ? "pointer" : "default",
                        boxSizing: "border-box",
                    }}
                >
                    Submit
                </button>
            </div>
        </ModalSheet>
    )
}

// --- HOMEPAGE JOBS COMPONENT ---

interface HomepageJob {
    id: string
    title: string
    company: {
        name: string
        logo_url: string | null
        description: string | null
        website_url: string | null
        linkedin_url: string | null
        x_url: string | null
        instagram_url?: string | null
        tiktok_url?: string | null
        github_url?: string | null
        youtube_url?: string | null
        glassdoor_url?: string | null
        crunchbase_url?: string | null
        huggingface_url?: string | null
        facebook_url?: string | null
        employee_count_range?: string | null
        founded_year?: number | null
        headquarters?: {
            address: string | null
            city: string | null
            country: string | null
            lat?: number | null
            lng?: number | null
        } | null
        industry?: string | null
        company_type?: string | null
        total_funding_usd?: number | null
    }
    posted_at: string | null
    apply_url: string
    locations: string[] | null
    employment_type: string | null
    workplace_type: string | null
    salary: { display: string } | null
    job_summary: string | null
    visa_sponsorship?: string | null
    seniority_level?: string | null
    /** Geocoded coordinates of the primary job location. Present for most jobs. */
    location_lat?: number | null
    location_lng?: number | null
    /** Distinct points from GET /jobs/:id when multiple locations resolve — map + commute. */
    location_points?: Array<{ lat: number; lng: number }> | null
}

interface JobDescriptionDetail {
    responsibilities: string[]
    minimum_qualifications: string[]
    preferred_qualifications: string[]
}

/**
 * One entry per company from GET /jobs/map.
 * Replaces the old HomepageJob[] approach for the map — avoids the 50-job MAX_LIMIT
 * and always returns all ~200-300 companies with recent jobs in one request.
 */
interface MapCompanyEntry {
    company_id: string
    company_name: string
    company_logo_url: string | null
    company_slug: string
    /** Centroid of the job-location bucket — where the chip is placed on the map.
     *  Uses per-job geocoded coords when available, falls back to company HQ. */
    chip_lat: number
    chip_lng: number
    /** Company canonical HQ — used for address-precision check + fallback display. */
    headquarters: {
        lat: number
        lng: number
        city: string | null
        country: string | null
        address: string | null
    } | null
    job_count: number
}

/** Persist opened job detail so swiping away and back does not refetch. */
const JOB_DETAIL_CACHE_STORAGE_KEY = "curastem_job_detail_cache_v2"
const JOB_DETAIL_CACHE_TTL_MS = 7 * 24 * 60 * 60 * 1000
const JOB_DETAIL_CACHE_MAX_JOBS = 48

type JobDetailCacheEntry = {
    t: number
    /** jobsApiUrl used for fetch — ignore entry if it changed */
    u: string
    /** true once AI enrichment fields are confirmed populated in this entry */
    aiDone: boolean
    desc: JobDescriptionDetail | null
    detailSummary: string | null
    detailCompanyDesc: string | null
    detailVisaSponsorship: string | null
    apiKeywords: string[]
    /** AI-extracted per-job location fields */
    detailExperienceYearsMin: number | null
    detailJobAddress: string | null
    detailJobCity: string | null
    detailJobState: string | null
    detailJobCountry: string | null
    detailSeniorityLevel: string | null
    detailLocations: string[] | null
    detailSalary: { display: string } | null
    detailLocationPoints: Array<{ lat: number; lng: number }> | null
    /** Full company object from the detail API response — fills gaps when opened from a chat snippet */
    company: HomepageJob["company"] | null
}

type JobDetailCacheRoot = Record<string, JobDetailCacheEntry>

function readJobDetailCache(
    jobId: string,
    jobsApiUrl: string
): JobDetailCacheEntry | null {
    if (typeof localStorage === "undefined") return null
    try {
        const raw = localStorage.getItem(JOB_DETAIL_CACHE_STORAGE_KEY)
        if (!raw) return null
        const root = JSON.parse(raw) as JobDetailCacheRoot
        const e = root[jobId]
        if (!e || typeof e.t !== "number") return null
        if (e.u !== jobsApiUrl) return null
        if (Date.now() - e.t > JOB_DETAIL_CACHE_TTL_MS) return null
        return e
    } catch {
        return null
    }
}

function writeJobDetailCache(
    jobId: string,
    jobsApiUrl: string,
    payload: Omit<JobDetailCacheEntry, "t" | "u">
): void {
    if (typeof localStorage === "undefined") return
    try {
        let root: JobDetailCacheRoot = {}
        const raw = localStorage.getItem(JOB_DETAIL_CACHE_STORAGE_KEY)
        if (raw) root = JSON.parse(raw) as JobDetailCacheRoot
        root[jobId] = {
            t: Date.now(),
            u: jobsApiUrl,
            aiDone: payload.aiDone,
            desc: payload.desc,
            detailSummary: payload.detailSummary,
            detailCompanyDesc: payload.detailCompanyDesc,
            detailVisaSponsorship: payload.detailVisaSponsorship,
            apiKeywords: Array.isArray(payload.apiKeywords)
                ? payload.apiKeywords
                : [],
            detailExperienceYearsMin: payload.detailExperienceYearsMin ?? null,
            detailJobAddress: payload.detailJobAddress ?? null,
            detailJobCity: payload.detailJobCity ?? null,
            detailJobState: payload.detailJobState ?? null,
            detailJobCountry: payload.detailJobCountry ?? null,
            detailSeniorityLevel: payload.detailSeniorityLevel ?? null,
            detailLocations: Array.isArray(payload.detailLocations)
                ? payload.detailLocations
                : null,
            detailSalary: payload.detailSalary ?? null,
            detailLocationPoints: Array.isArray(payload.detailLocationPoints)
                ? payload.detailLocationPoints
                : null,
            company: payload.company ?? null,
        }
        const ids = Object.keys(root)
        if (ids.length > JOB_DETAIL_CACHE_MAX_JOBS) {
            ids.sort((a, b) => root[a]!.t - root[b]!.t)
            const drop = ids.length - JOB_DETAIL_CACHE_MAX_JOBS
            for (let i = 0; i < drop; i++) delete root[ids[i]!]
        }
        localStorage.setItem(JOB_DETAIL_CACHE_STORAGE_KEY, JSON.stringify(root))
    } catch {
        // Quota, private mode, or parse errors — ignore.
    }
}

// -----------------------------------------------------------------------------
// Job chip store — persists minimal HomepageJob data so chip clicks survive reload
// -----------------------------------------------------------------------------
const JOB_CHIP_STORE_KEY = "curastem_job_chip_store_v1"

function readJobChipStore(): Record<string, HomepageJob> {
    if (typeof localStorage === "undefined") return {}
    try {
        const raw = localStorage.getItem(JOB_CHIP_STORE_KEY)
        return raw ? (JSON.parse(raw) as Record<string, HomepageJob>) : {}
    } catch {
        return {}
    }
}

function writeJobChipStore(job: HomepageJob): void {
    if (typeof localStorage === "undefined") return
    try {
        const store = readJobChipStore()
        store[job.id] = job
        // Cap at 100 entries (cheap — each entry is tiny)
        const ids = Object.keys(store)
        if (ids.length > 100) {
            // No timestamps here; just drop the oldest by insertion order
            delete store[ids[0]!]
        }
        localStorage.setItem(JOB_CHIP_STORE_KEY, JSON.stringify(store))
    } catch {
        // Quota or private mode — ignore
    }
}

/** In-memory + first-paint state for JobDetailScrollBody (sync hydrate from cache). */
type JobDetailHydrationState = {
    desc: JobDescriptionDetail | null
    detailSummary: string | null
    detailCompanyDesc: string | null
    detailVisaSponsorship: string | null
    loadingDesc: boolean
    apiKeywords: string[]
    detailExperienceYearsMin: number | null
    detailJobAddress: string | null
    detailJobCity: string | null
    detailJobState: string | null
    detailJobCountry: string | null
    detailSeniorityLevel: string | null
    detailLocations: string[] | null
    detailSalary: { display: string } | null
    detailLocationPoints: Array<{ lat: number; lng: number }> | null
}

function jobDetailFetchPendingState(): JobDetailHydrationState {
    return {
        desc: null,
        detailSummary: null,
        detailCompanyDesc: null,
        detailVisaSponsorship: null,
        apiKeywords: [],
        loadingDesc: true,
        detailExperienceYearsMin: null,
        detailJobAddress: null,
        detailJobCity: null,
        detailJobState: null,
        detailJobCountry: null,
        detailSeniorityLevel: null,
        detailLocations: null,
        detailSalary: null,
        detailLocationPoints: null,
    }
}

function jobDetailStateFromCacheEntry(
    c: JobDetailCacheEntry
): JobDetailHydrationState {
    return {
        desc: c.desc,
        detailSummary: c.detailSummary,
        detailCompanyDesc: c.detailCompanyDesc,
        detailVisaSponsorship: c.detailVisaSponsorship,
        apiKeywords: Array.isArray(c.apiKeywords) ? c.apiKeywords : [],
        loadingDesc: false,
        detailExperienceYearsMin: c.detailExperienceYearsMin ?? null,
        detailJobAddress: c.detailJobAddress ?? null,
        detailJobCity: c.detailJobCity ?? null,
        detailJobState: c.detailJobState ?? null,
        detailJobCountry: c.detailJobCountry ?? null,
        detailSeniorityLevel: c.detailSeniorityLevel ?? null,
        detailLocations: Array.isArray(c.detailLocations)
            ? c.detailLocations
            : null,
        detailSalary: c.detailSalary ?? null,
        detailLocationPoints: Array.isArray(c.detailLocationPoints)
            ? c.detailLocationPoints
            : null,
    }
}

/** No cache and fetch not allowed yet (swipe preview) — avoid perpetual loadingDesc. */
function jobDetailDeferredState(): JobDetailHydrationState {
    return {
        desc: null,
        detailSummary: null,
        detailCompanyDesc: null,
        detailVisaSponsorship: null,
        apiKeywords: [],
        loadingDesc: false,
        detailExperienceYearsMin: null,
        detailJobAddress: null,
        detailJobCity: null,
        detailJobState: null,
        detailJobCountry: null,
        detailSeniorityLevel: null,
        detailLocations: null,
        detailSalary: null,
        detailLocationPoints: null,
    }
}

function jobDetailInitialState(
    jobId: string,
    jobsApiUrl: string,
    fetchEnabled: boolean
): JobDetailHydrationState {
    const c = readJobDetailCache(jobId, jobsApiUrl)
    if (c) return jobDetailStateFromCacheEntry(c)
    if (!fetchEnabled) return jobDetailDeferredState()
    return jobDetailFetchPendingState()
}

