    const [locationInfo, setLocationInfo] = React.useState<LocationInfo | null>(
        null
    )
    const locationFetchedRef = React.useRef(false)
    /** Job IDs already surfaced via search_jobs in this chat — sent as exclude_ids so "find more" is not a duplicate page. */
    const searchJobsSeenJobIdsRef = React.useRef<Set<string>>(new Set())
    /** Latest user speech text in Gemini Live — for search_jobs geo hint ("near me"). */
    const liveUserUtteranceForGeoRef = React.useRef("")

    /** GET `${jobsApiUrl}/geo` — server IP lat/lng (same as homepage). */
    const jobsProxyGeoRef = React.useRef<{ lat: number; lng: number } | null>(
        null
    )
    const jobsGeoFetchStartedRef = React.useRef(false)
    /** Browser geolocation — filled only after a search_jobs "near me" tool call requests it (not on app load). */
    const chatBrowserGeoRef = React.useRef<{ lat: number; lng: number } | null>(
        null
    )
    /** GPS from map "current location" — map only; chat search_jobs near me uses /geo + IP, not this ref. */
    const preciseLocRef = React.useRef<{ lat: number; lng: number } | null>(
        null
    )

    React.useEffect(() => {
        if (!jobsApiUrl || jobsGeoFetchStartedRef.current) return
        jobsGeoFetchStartedRef.current = true
        const ctrl = new AbortController()
        const timer = setTimeout(() => ctrl.abort(), 5000)
        fetch(`${jobsApiUrl}/geo`, { signal: ctrl.signal })
            .finally(() => clearTimeout(timer))
            .then((r) => (r.ok ? r.json() : null))
            .then((d: { lat?: unknown; lng?: unknown } | null) => {
                if (!d) return
                const lat = Number(d.lat)
                const lng = Number(d.lng)
                if (
                    Number.isFinite(lat) &&
                    Number.isFinite(lng) &&
                    lat >= -90 &&
                    lat <= 90 &&
                    lng >= -180 &&
                    lng <= 180
                ) {
                    jobsProxyGeoRef.current = { lat, lng }
                }
            })
            .catch(() => {})
    }, [jobsApiUrl])

    const fetchLocation = React.useCallback(async () => {
        if (typeof window === "undefined" || locationFetchedRef.current) return
        locationFetchedRef.current = true

        const cached = readLocationCache()
        const isFresh =
            cached?.fetchedAt != null &&
            Date.now() - cached.fetchedAt <= GEOLOCATION_REFRESH_INTERVAL_MS

        if (isFresh && cached) {
            setLocationInfo(cached)
            return
        }

        // Use cached location optimistically while fetching new data
        if (cached) setLocationInfo(cached)

        const fresh = await fetchGeolocationFromAPI()
        if (fresh) {
            setLocationInfo(fresh)
            writeLocationCache(fresh)
        }
    }, [])

    // ---------------------------------------------------------------------------
    // getSystemPromptWithContext(forVoice?)
    //
    // forVoice=false (default) → text chat path. Includes <curastem-suggestions>
    //   delimiter instructions so the model appends suggestions JSON at the end of
    //   every response (parsed in the stream loop below). App/doc creation uses real
    //   API tool calls (create_app, update_doc).
    //
    // forVoice=true → Gemini Live (audio) path. All delimiter tags are OMITTED
    //   because Gemini Live uses responseModalities: ["AUDIO"] and would speak the
    //   tag names verbatim. Suggestions are generated via fetchAiSuggestions() instead.
    // ---------------------------------------------------------------------------
    const getSystemPromptWithContext = React.useCallback(
        (forVoice = false) => {
            if (role === "volunteer") return systemPrompt || ""
            const now = new Date()
            let prompt = systemPrompt || ""
            prompt += `\n\n[System Context]\nCurrent Date: ${now.toLocaleDateString(undefined, { weekday: "long", year: "numeric", month: "long", day: "numeric" })}\nCurrent Time: ${now.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}`
            if (locationInfo) {
                prompt += `\nLocation: ${locationInfo.city}, ${locationInfo.region}, ${locationInfo.country}`
                if (
                    locationInfo.lat != null &&
                    locationInfo.lng != null &&
                    !Number.isNaN(locationInfo.lat) &&
                    !Number.isNaN(locationInfo.lng)
                ) {
                    prompt += `\nApproximate coordinates (IP geolocation): ${locationInfo.lat}, ${locationInfo.lng}.`
                }
            }

            // Inject favorite things so AI can personalise without calling retrieve_memories every turn
            const favorites = getMemories()
            if (favorites.length > 0) {
                prompt += `\n\n[User's Favorite Things & Personal Facts]\n${favorites.join("\n")}`
            }

            // Text chat: do not inline full resume — use retrieve_resume (same storage).
            // Gemini Live only exposes search_jobs + get_job_details, so voice still needs
            // the text in-system for resume/cover-letter help.
            const resumeText = getResume()?.trim() ?? ""
            if (resumeText) {
                if (forVoice) {
                    prompt += `\n\n[User's Saved Resume]\n${resumeText}`
                } else {
                    prompt += `\n\n[Saved resume on device]\nPlain text is stored on-device. Call retrieve_resume when the user's request needs their full work history or skills (e.g. new resume, cover letter, tailored job advice). Do not assume resume content otherwise.`
                }
            }

            // Surface only the job ID — the model must call get_job_details to
            // get the actual data. Pre-injecting title/description would defeat
            // the purpose of the tool and risk serving stale data.
            if (selectedJobRef.current) {
                const j = selectedJobRef.current
                prompt += `\n\n[Currently Viewed Job]\nJob ID: ${j.id}\nThe user has a job open in the right sidebar. When they ask about "this job", "it", or "the job", call get_job_details with job_id: "${j.id}" to get the full details before responding.`
            }

            if (forVoice) {
                // Voice session: natural speech only — no XML tags, no delimiters.
                // Suggestions are generated separately via fetchAiSuggestions().
                // App/doc creation is not supported mid-voice; guide the user to text chat.
                prompt += `

[VOICE SESSION — SPEAK NATURALLY]
This is a live voice call. Rules:
- Respond naturally and conversationally — no lists, no headers, no markdown.
- NEVER output any XML tags such as <curastem-app>, <curastem-doc>, or <curastem-suggestions>. These are text-chat-only features and will be read aloud verbatim if you output them, which is broken.
- If the user asks you to build an app, create a document, or do anything that requires the app/doc editor, acknowledge warmly and let them know they can send a message in text chat to create it.
- Keep responses concise and easy to follow by ear.`
            } else {
                prompt += `

FOLLOW-UP SUGGESTIONS (required at the end of EVERY response, no exceptions):
<curastem-suggestions>
["Short question 1?","Short question 2?","Short question 3?"]
</curastem-suggestions>
Rules: always 3–5 suggestions, each under 5 words, specific to what you just said, plain strings only. Do NOT wrap in markdown code fences.`
            }

            return prompt
        },
        // selectedJobRef is a ref — no need to list in deps; it's always current.
        [systemPrompt, locationInfo, role, isJobOpen, selectedJob]
    )

    const docContentRef = React.useRef(docContent)
    React.useEffect(() => {
        docContentRef.current = docContent
    }, [docContent])

    const docTypeRef = React.useRef(docType)
    React.useEffect(() => {
        docTypeRef.current = docType
    }, [docType])

    const docCompanyRef = React.useRef(docCompany)
    React.useEffect(() => {
        docCompanyRef.current = docCompany
    }, [docCompany])

    const chatDocsRef = React.useRef<ChatDocEntry[]>([])
    React.useEffect(() => {
        chatDocsRef.current = chatDocs
    }, [chatDocs])

    const activeDocIdRef = React.useRef<string | null>(null)
    React.useEffect(() => {
        activeDocIdRef.current = activeDocId
    }, [activeDocId])

    const applyChatDocHydration = React.useCallback((chat: ChatSession) => {
        const { docs, activeDocId: nextActive } = migrateLegacyChatDocs(chat)
        setChatDocs(docs)
        setActiveDocId(nextActive)
        const active = nextActive
            ? docs.find((d) => d.id === nextActive)
            : pickMostRecentDocEntry(docs)
        if (active) {
            setDocContent(active.content)
            setDocType(active.docType)
            setDocCompany(active.docCompany ?? "")
        } else {
            setDocContent(DEFAULT_DOC_CONTENT)
            setDocType("doc")
            setDocCompany("")
        }
    }, [])

    const switchToDoc = React.useCallback((docId: string) => {
        const doc = chatDocsRef.current.find((d) => d.id === docId)
        if (!doc) return
        setActiveDocId(docId)
        setDocContent(doc.content)
        setDocType(doc.docType)
        setDocCompany(doc.docCompany ?? "")
    }, [])

    /** Ensures opening Docs focuses the most recently edited document in this chat. */
    const openMostRecentDoc = React.useCallback(() => {
        const docs = chatDocsRef.current
        if (docs.length === 0) {
            const id = generateChatDocId()
            const html = docContentRef.current || DEFAULT_DOC_CONTENT
            setChatDocs([
                {
                    id,
                    content: html,
                    docType: docTypeRef.current,
                    docCompany: docCompanyRef.current?.trim() || undefined,
                    lastEdited: Date.now(),
                },
            ])
            setActiveDocId(id)
            return
        }
        const pick = pickMostRecentDocEntry(docs)
        if (pick) switchToDoc(pick.id)
    }, [switchToDoc])

    /**
     * Registers HTML into the multi-doc list. Use mode "new" for create_resume / cover;
     * "update" for update_doc (mutates active doc, or creates one if none).
     */
    const upsertDocForTool = React.useCallback(
        (
            mode: "new" | "update",
            html: string,
            dType: "doc" | "resume" | "cover_letter",
            company: string,
            opts?: { targetDocId?: string | null }
        ): string => {
            const now = Date.now()
            const co = company?.trim() ?? ""
            if (mode === "new") {
                const id = generateChatDocId()
                setChatDocs((prev) => [
                    ...prev,
                    {
                        id,
                        content: html,
                        docType: dType,
                        docCompany: co || undefined,
                        lastEdited: now,
                    },
                ])
                setActiveDocId(id)
                setDocContent(html)
                setDocType(dType)
                setDocCompany(co)
                return id
            }
            const tid = opts?.targetDocId ?? activeDocIdRef.current
            if (
                !tid ||
                !chatDocsRef.current.some((d) => d.id === tid)
            ) {
                const id = generateChatDocId()
                setChatDocs((prev) => [
                    ...prev,
                    {
                        id,
                        content: html,
                        docType: dType,
                        docCompany: co || undefined,
                        lastEdited: now,
                    },
                ])
                setActiveDocId(id)
                setDocContent(html)
                setDocType(dType)
                setDocCompany(co)
                return id
            }
            setActiveDocId(tid)
            setChatDocs((prev) =>
                prev.map((d) =>
                    d.id === tid
                        ? {
                              ...d,
                              content: html,
                              docType: dType,
                              docCompany: co || undefined,
                              lastEdited: now,
                          }
                        : d
                )
            )
            setDocContent(html)
            setDocType(dType)
            setDocCompany(co)
            return tid
        },
        []
    )

    const appCodeRef = React.useRef(appCode)
    React.useEffect(() => {
        appCodeRef.current = appCode
    }, [appCode])

    const appModeRef = React.useRef(appMode)
    React.useEffect(() => {
        appModeRef.current = appMode
    }, [appMode])

    const isWhiteboardOpenRef = React.useRef(false)
    const docTimeoutRef = React.useRef<any>(null) // Debounce/Throttle for doc editor
    const lastDocSendTimeRef = React.useRef<number>(0)
    const appTimeoutRef = React.useRef<any>(null) // Debounce/Throttle for app editor
    const lastAppSendTimeRef = React.useRef<number>(0)
    const inputTimeoutRef = React.useRef<any>(null)
    const lastInputSendTimeRef = React.useRef<number>(0)
    const lastAISendTimeRef = React.useRef<number>(0)
    React.useEffect(() => {
        isWhiteboardOpenRef.current = isWhiteboardOpen
    }, [isWhiteboardOpen])

    const hasWhiteboardStartedRef = React.useRef(false)
    React.useEffect(() => {
        hasWhiteboardStartedRef.current = hasWhiteboardStarted
    }, [hasWhiteboardStarted])

    const pendingSnapshotRef = React.useRef<any>(null)
    const isScreenSharingRef = React.useRef(false)
    const saveChatHistoryRef = React.useRef<(title?: string) => void>(() => {})
    const generatingTitleForRef = React.useRef(new Set<string>())

    React.useEffect(() => {
        isScreenSharingRef.current = isScreenSharing
    }, [isScreenSharing])

    // --- VIEWPORT & SCROLL HANDLING ---
    // Fix for iOS Safari keyboard shifting the viewport
    React.useEffect(() => {
        if (typeof window === "undefined" || !window.visualViewport) return

        const handleResize = () => {
            if (containerRef.current && window.visualViewport) {
                // Adjust container height to match visual viewport
                // This prevents the keyboard from pushing content off-screen on iOS Safari
                // We set the height explicitly because 100vh includes the area under the keyboard
                containerRef.current.style.height = `${window.visualViewport.height}px`

                // Force scroll to top to counteract any browser auto-scroll behavior
                // when the keyboard opens, keeping the UI anchored correctly
                window.scrollTo(0, 0)
            }
        }

        window.visualViewport.addEventListener("resize", handleResize)
        window.visualViewport.addEventListener("scroll", handleResize)

        return () => {
            if (window.visualViewport) {
                window.visualViewport.removeEventListener(
                    "resize",
                    handleResize
                )
                window.visualViewport.removeEventListener(
                    "scroll",
                    handleResize
                )
            }
        }
    }, [])

    // Koah ad SDK injection — configure theme before script loads, then inject once
    React.useEffect(() => {
        if (typeof document === "undefined" || !koahPublisherId || !showAds)
            return
        ;(window as any).koah_init = (window as any).koah_init || {}
        ;(window as any).koah_init.theme = {
            colorScheme: "dark",
            presentationMode: "borderless",
            accentColor,
            fontFamily: "inherit",
            maxWidth: "100%",
        }
        if (document.querySelector('script[src*="app.koah.ai"]')) return
        const script = document.createElement("script")
        script.async = true
        script.src = `https://app.koah.ai/js?token=${koahPublisherId}`
        document.head.appendChild(script)
        return () => {
            if (document.head.contains(script)) {
                document.head.removeChild(script)
            }
        }
    }, [koahPublisherId, showAds, accentColor])

    // Google Sans Code font injection
    React.useEffect(() => {
        if (typeof document === "undefined") return

        // Check if already injected
        const existingLink = document.querySelector(
            'link[href*="Google+Sans+Code"]'
        )
        if (existingLink) return

        const link = document.createElement("link")
        link.href =
            "https://fonts.googleapis.com/css2?family=Google+Sans+Code:wght@400&display=swap"
        link.rel = "stylesheet"
        document.head.appendChild(link)

        return () => {
            if (document.head.contains(link)) {
                document.head.removeChild(link)
            }
        }
    }, [])

    // Tldraw sync
    React.useEffect(() => {
        // Inject Tldraw CSS
        const link = document.createElement("link")
        link.href = "https://esm.sh/tldraw@2.1.0/tldraw.css"
        link.rel = "stylesheet"
        document.head.appendChild(link)

        if (!editor) {
            return () => {
                if (document.head.contains(link)) {
                    document.head.removeChild(link)
                }
            }
        }

        // Load pending snapshot if exists
        if (pendingSnapshotRef.current) {
            log("Applying pending Tldraw snapshot...")
            try {
                // Same filtering logic as above for pending snapshot
                const snapshot = pendingSnapshotRef.current
                editor.store.mergeRemoteChanges(() => {
                    const records = Object.values(snapshot)
                    const contentRecords = records.filter(
                        (r: any) =>
                            r.typeName === "shape" ||
                            r.typeName === "asset" ||
                            r.typeName === "page" ||
                            r.typeName === "document"
                    )
                    if (contentRecords.length > 0) {
                        editor.store.put(contentRecords)
                    }
                })
                log("Merged pending tldraw snapshot content successfully")
            } catch (e) {
                log(`Error merging pending tldraw snapshot: ${e}`)
            }
            pendingSnapshotRef.current = null
        }

        const cleanup = editor.store.listen((update: any) => {
            // Only broadcast local changes (source='user')
            if (update.source === "user") {
                // Filter changes to exclude presence/camera updates which shouldn't be synced
                // Tldraw v2 uses types like 'instance', 'camera', 'pointer', etc.

                const filteredChanges: any = {
                    added: {},
                    updated: {},
                    removed: {},
                }
                let hasChanges = false

                const isSyncable = (typeName: string) => {
                    // Sync content, allow most types but exclude local user state
                    const localTypes = new Set([
                        "instance",
                        "instance_page_state",
                        "user",
                        "user_document",
                        "user_presence",
                        "camera",
                        "pointer",
                    ])
                    return !localTypes.has(typeName)
                }

                // Filter Added
                Object.values(update.changes.added).forEach((record: any) => {
                    if (isSyncable(record.typeName)) {
                        filteredChanges.added[record.id] = record
                        hasChanges = true
                    }
                })

                // Filter Updated
                Object.entries(update.changes.updated).forEach(
                    ([id, diff]: [string, any]) => {
                        // diff is [from, to]
                        if (isSyncable(diff[1].typeName)) {
                            filteredChanges.updated[id] = diff
                            hasChanges = true
                        }
                    }
                )

                // Filter Removed
                Object.values(update.changes.removed).forEach((record: any) => {
                    if (isSyncable(record.typeName)) {
                        filteredChanges.removed[record.id] = record
                        hasChanges = true
                    }
                })

                if (
                    hasChanges &&
                    dataConnectionRef.current &&
                    dataConnectionRef.current.open
                ) {
                    // log(`Sending update: ${Object.keys(filteredChanges.added).length} added, ${Object.keys(filteredChanges.updated).length} updated`)
                    dataConnectionRef.current.send({
                        type: "tldraw-update",
                        payload: filteredChanges,
                    })
                }
            }
        })

        return () => {
            cleanup()
            if (document.head.contains(link)) {
                document.head.removeChild(link)
            }
        }
    }, [editor])

    // --- STATE: GEMINI LIVE ---
    const [isLiveMode, setIsLiveMode] = React.useState(false)
    const lastLiveUpdateRef = React.useRef(Date.now())

    // True whenever the user is in or waiting for a P2P call — censoring is only active then.
    const isP2PContext = (status !== "idle" || !!role) && !isLiveMode

    const wasInP2PRef = React.useRef(false)
    React.useEffect(() => {
        const inP2P = (status !== "idle" || !!role) && !isLiveMode
        if (inP2P && !wasInP2PRef.current) {
            setShowAddPeopleOverlay(true)
        } else if (!inP2P && wasInP2PRef.current) {
            setShowAddPeopleOverlay(false)
        }
        wasInP2PRef.current = inP2P
    }, [status, role, isLiveMode])

    React.useEffect(() => {
        if (!isLiveMode) return

        const checkTimeUpdate = () => {
            if (typeof window === "undefined") return

            const now = Date.now()
            // Update every 10 minutes (600,000ms) as requested
            // Note: We check every minute, but only send if 10m elapsed
            if (
                now - lastLiveUpdateRef.current > 600000 &&
                liveClientRef.current &&
                liveClientRef.current.readyState === WebSocket.OPEN
            ) {
                lastLiveUpdateRef.current = now

                const date = new Date()
                const timeContext = `[System Update] Current Date: ${date.toLocaleDateString()}, Current Time: ${date.toLocaleTimeString()}`

                // gemini-3.1-flash-live: clientContent is only for initial history seeding;
                // mid-conversation text injections must use realtimeInput.
                liveClientRef.current.send(
                    JSON.stringify({
                        realtimeInput: {
                            text: timeContext,
                        },
                    })
                )
                if (debugPanel === "p2p")
                    log("Sent time update to Gemini Live session")
            }
        }

        const interval = setInterval(checkTimeUpdate, 60000) // Check every minute
        return () => clearInterval(interval)
    }, [isLiveMode, debugPanel])

    const [userIsSpeaking, setUserIsSpeaking] = React.useState(false)
    const [isLiveGenerating, setIsLiveGenerating] = React.useState(false)
    const [isAiSpeaking, setIsAiSpeaking] = React.useState(false) // Visual indicator for audio playback

    const liveClientRef = React.useRef<WebSocket | null>(null)
    const liveAudioContextRef = React.useRef<AudioContext | null>(null)
    const liveSourceRef = React.useRef<MediaStreamAudioSourceNode | null>(null)
    const liveProcessorRef = React.useRef<ScriptProcessorNode | null>(null)
    const liveInputStreamRef = React.useRef<MediaStream | null>(null)
    const activeAudioSourcesRef = React.useRef<AudioBufferSourceNode[]>([])
    const liveNextPlayTimeRef = React.useRef<number>(0)
    const transcriptionTimeoutRef = React.useRef<any>(null)
    const silenceTimerRef = React.useRef<any | null>(null)
    /** When true, the next user transcript chunk opens a new bubble (barge-in / new turn). */
    const forceNewUserTranscriptBubbleRef = React.useRef(false)
    const suggestionsGeneratedForTurnRef = React.useRef(false)
    const lastUserSpeechTimeRef = React.useRef(0)
    const userIsSpeakingRef = React.useRef(false)
    const isLiveGeneratingRef = React.useRef(false)

    const stopAllAudio = React.useCallback(() => {
        if (typeof window !== "undefined" && window.speechSynthesis) {
            window.speechSynthesis.cancel()
        }
        activeAudioSourcesRef.current.forEach((source) => {
            try {
                source.stop()
            } catch (e) {
                // Ignore
            }
        })
        activeAudioSourcesRef.current = []
        setIsAiSpeaking(false)
        // Reset play time so next audio plays immediately
        if (liveAudioContextRef.current) {
            liveNextPlayTimeRef.current =
                liveAudioContextRef.current.currentTime + 0.1
        }
    }, [])

    const captureCurrentContext = React.useCallback(async () => {
        try {
            // Priority 1: Screen Share
            if (isScreenSharingRef.current && screenStreamRef.current) {
                const track = screenStreamRef.current.getVideoTracks()[0]
                if (track && track.readyState === "live") {
                    return new Promise<string | null>((resolve) => {
                        const vid = document.createElement("video")
                        vid.muted = true
                        vid.playsInline = true
                        vid.srcObject = screenStreamRef.current
                        vid.onloadedmetadata = () => {
                            vid.play()
                                .then(() => {
                                    const cvs = document.createElement("canvas")
                                    cvs.width = vid.videoWidth
                                    cvs.height = vid.videoHeight
                                    const ctx = cvs.getContext("2d")
                                    ctx?.drawImage(vid, 0, 0)
                                    resolve(
                                        cvs
                                            .toDataURL("image/jpeg", 0.6)
                                            .split(",")[1]
                                    )
                                    // Cleanup
                                    vid.pause()
                                    vid.srcObject = null
                                    vid.remove()
                                })
                                .catch((e) => {
                                    console.warn("Video play failed", e)
                                    resolve(null)
                                })
                        }
                        vid.onerror = () => resolve(null)
                    })
                }
            }

            // Priority 2: Whiteboard
            if (isWhiteboardOpenRef.current && whiteboardContainerRef.current) {
                // Try to find canvas (Tldraw usually renders a canvas)
                const canvas =
                    whiteboardContainerRef.current.querySelector("canvas")
                if (canvas) {
                    return canvas.toDataURL("image/jpeg", 0.6).split(",")[1]
                }
                // If no canvas (e.g. SVG mode), try exportToBlob if available
                if (editorRef.current && exportToBlob) {
                    try {
                        // @ts-ignore
                        const shapes = Array.from(
                            editorRef.current.getCurrentPageShapes()
                        )
                        if (shapes.length > 0) {
                            const ids = shapes.map((s: any) => s.id)
                            const blob = await exportToBlob({
                                editor: editorRef.current,
                                ids,
                                format: "jpeg",
                                opts: { background: true },
                            })
                            return new Promise((resolve) => {
                                const reader = new FileReader()
                                reader.onloadend = () =>
                                    resolve(
                                        (reader.result as string).split(",")[1]
                                    )
                                reader.readAsDataURL(blob)
                            })
                        }
                    } catch (e) {}
                }
            }
        } catch (e) {
            console.error("Capture context error", e)
        }
        return null
    }, [])

    const fetchAiSuggestions = React.useCallback(
        async (lastAiMessageContent: string) => {
            if (!lastAiMessageContent.trim()) {
                return
            }

            // Capture context if available
            const visualContext = await captureCurrentContext()

            try {
                const systemInstruction = `You are a helpful AI assistant.
Your goal is to suggest 3 short, relevant follow-up responses the USER might want to say next.
Keep suggestions brief and useful (under 5 words).
Output ONLY a JSON array of strings: ["suggestion 1", "suggestion 2", "suggestion 3"].
Do not include markdown formatting or explanations.`

                const userContent: any[] = [
                    {
                        text: `The AI just said: "${lastAiMessageContent}". What are 3 relevant follow-up things I (the user) might say next?`,
                    },
                ]

                if (visualContext) {
                    userContent.push({
                        inlineData: {
                            mimeType: "image/jpeg",
                            data: visualContext,
                        },
                    })
                }

                // If document is open, include it for context
                if (isDocOpen) {
                    userContent.push({
                        text: `Current document content: \n${docContent}`,
                    })
                }

                const response = await fetch(
                    `${geminiProxyUrl(SUGGESTION_MODEL_ID, "generateContent")}`,
                    {
                        method: "POST",
                        headers: { "Content-Type": "application/json" },
                        body: JSON.stringify({
                            contents: [{ role: "user", parts: userContent }],
                            systemInstruction: {
                                parts: [{ text: systemInstruction }],
                            },
                            generationConfig: {
                                responseMimeType: "application/json",
                                thinkingConfig: {
                                    thinkingBudget: 0,
                                },
                            },
                        }),
                    }
                )

                if (!response.ok) return

                const data = await response.json()
                const text = data.candidates?.[0]?.content?.parts?.[0]?.text
                if (text) {
                    const parsed = JSON.parse(text)
                    if (Array.isArray(parsed)) {
                        // Filter to strings and cap at 5 suggestions
                        const suggs = parsed
                            .filter((s: any) => typeof s === "string")
                            .slice(0, 5)
                        if (suggs.length > 0) {
                            setAiGeneratedSuggestions(suggs)
                            broadcastData({
                                type: "ai-suggestions",
                                payload: suggs,
                            })
                        }
                    }
                }
            } catch (error) {
                console.error("Suggestion fetch error:", error)
            }
        },
        // NOTE: broadcastData is defined later in this component (line ~15974) so it
        // cannot be placed in the deps array (TDZ). broadcastData is a stable useCallback
        // reference, so capturing it via closure is safe and causes no stale-closure bugs.
        // eslint-disable-next-line react-hooks/exhaustive-deps
        [geminiProxyUrl, captureCurrentContext, isDocOpen, docContent]
    )

    const stopLiveSession = React.useCallback(() => {
        haptic.warning()
        if (silenceTimerRef.current) {
            clearTimeout(silenceTimerRef.current)
            silenceTimerRef.current = null
        }
        stopAllAudio()
        if (liveClientRef.current) {
            if (liveClientRef.current.readyState === WebSocket.OPEN) {
                liveClientRef.current.send(
                    JSON.stringify({ realtimeInput: { audioStreamEnd: true } })
                )
            }
            liveClientRef.current.close()
            liveClientRef.current = null
        }
        if (liveProcessorRef.current) {
            liveProcessorRef.current.disconnect()
            liveProcessorRef.current = null
        }
        if (liveSourceRef.current) {
            liveSourceRef.current.disconnect()
            liveSourceRef.current = null
        }
        if (liveInputStreamRef.current) {
            liveInputStreamRef.current
                .getTracks()
                .forEach((track) => track.stop())
            liveInputStreamRef.current = null
        }

        // Clear local stream if it was set by live session
        if (localStreamRef.current) {
            localStreamRef.current.getTracks().forEach((track) => track.stop())
            setLocalStream(null)
            localStreamRef.current = null
        }

        if (liveAudioContextRef.current) {
            liveAudioContextRef.current.close()
            liveAudioContextRef.current = null
        }
        if (transcriptionTimeoutRef.current) {
            clearTimeout(transcriptionTimeoutRef.current)
            transcriptionTimeoutRef.current = null
        }
        setIsLiveMode(false)
        isLiveGeneratingRef.current = false
        setIsLiveGenerating(false)
        userIsSpeakingRef.current = false
        setUserIsSpeaking(false)
        suggestionsGeneratedForTurnRef.current = false
        forceNewUserTranscriptBubbleRef.current = false
    }, [stopAllAudio])

    const cleanup = React.useCallback(
        (isManualHangup = false, keepTracks = false) => {
            if (
                statusRef.current === "connected" ||
                statusRef.current === "searching"
            ) {
                saveChatHistoryRef.current()
            }

            isManualHangupRef.current = isManualHangup
            const isAiSession = isLiveMode || !!liveClientRef.current

            log(`Cleanup called. Manual hangup: ${isManualHangup}`)

            // CLEAR HASH ON HANGUP (Group Call Logic)
            // If manual hangup, we want to leave the "room" so we don't auto-reconnect to the same group.
            // Exception: If we are the "owner" (first one) maybe we keep it?
            // User request: "dont have it keep the same hash except for user #1... we want other ppl to make a new hash"
            // Determining user #1 is tricky in mesh without explicit state.
            // SIMPLIFICATION: If *I* click end call, I leave the room.
            // So I should clear my hash to avoid re-joining the same mesh network immediately.
            // If I want to host again, I'll generate a new hash on next start.

            // However, the "owner" check is hard.
            // Let's assume if I manually hangup, I always clear hash.
            // If I am the "owner" and I hang up, the room effectively dies or I make a new one next time.

            if (isManualHangup && typeof window !== "undefined") {
                // Check if we have a hash
                // Clear hash if we are NOT a student (students keep their room/hash)
                if (
                    roleRef.current !== "student" &&
                    window.location.hash &&
                    window.location.hash.length > 1
                ) {
                    log("Manual hangup - clearing group hash to exit room")
                    window.history.replaceState(null, "", " ")
                }
            }

            // Reset private room connection state
            setIsPrivateRoomConnection(false)

            // Always attempt to stop live session to ensure state is reset
            stopLiveSession()

            if (!keepTracks) {
                if (localStreamRef.current) {
                    localStreamRef.current.getTracks().forEach((t) => t.stop())
                    localStreamRef.current = null
                }
                setLocalStream(null)
            }

            // Stop screen share when call ends
            // Manually stop screen share logic here instead of calling function that might not be defined
            if (screenStreamRef.current) {
                screenStreamRef.current
                    .getTracks()
                    .forEach((track: any) => track.stop())
                screenStreamRef.current = null
            }
            if (screenCallRef.current) {
                screenCallRef.current.close()
                screenCallRef.current = null
            }
            setIsScreenSharing(false)

            if (activeCall.current) {
                activeCall.current.close()
                activeCall.current = null
            }
            // Clear all active P2P calls
            activeCalls.current.forEach((call) => call.close())
            activeCalls.current.clear()

            // Clear remote streams
            remoteStreamsRef.current.clear()
            setRemoteStreams(new Map())
            setRemoteStream(null)
            setPendingPeerIds(new Set())

            if (dataConnectionRef.current) {
                dataConnectionRef.current.close()
                dataConnectionRef.current = null
            }

            if (peerInstance.current) {
                peerInstance.current.destroy()
                peerInstance.current = null
            }
            if (mqttClient.current) {
                mqttClient.current.end()
                mqttClient.current = null
            }

            // Clear state ONLY if it was NOT an AI session (P2P Reset)
            // AND not a multi-party private room call (preserve history for 3+)
            const isMultiPartyHistory =
                remoteStreamsRef.current.size + pendingPeerIds.size >= 2 // 2 remotes + 1 local = 3 people

            if (!isAiSession && !isMultiPartyHistory) {
                // Check if volunteer is hanging up without ever connecting (draft state)
                const isVolunteerDraft =
                    roleRef.current === "volunteer" &&
                    statusRef.current !== "connected"

                // Only clear state if NOT a student (keep student history for reconnection)
                // AND not a volunteer in draft state
                if (roleRef.current !== "student" && !isVolunteerDraft) {
                    // Clear whiteboard state
                    setIsWhiteboardOpen(false)
                    setHasWhiteboardStarted(false)
                    setEditor(null)
                    setIsDocOpen(false)
                    setDocContent(DEFAULT_DOC_CONTENT)

                    setMessages([])
                    setAttachments([])
                    setP2pLogs([])
                    setToolLogs([])
                }
            }

            setStatus("idle")

            // Explicitly force a UI refresh for the status change
            if (!isManualHangup && roleRef.current === "volunteer") {
                // If a volunteer gets disconnected remotely, we want them to feel like they are "waiting" again
                // But cleanup() stops the camera.
                // We need to restart it if we want continuous searching.
                // The handleCall.on('close') logic above handles the restart.
            }

            // ROLE RESET LOGIC:
            // If manual hangup, ALWAYS reset role (so they can select again).
            // If remote hangup (not manual), keep role to allow auto-reconnection for BOTH students and volunteers.
            if (isManualHangup) {
                // If I am a VOLUNTEER, clear my hash when I hang up manually
                let justClearedHash = false

                // ... (existing logic) ...

                // NOTE: For private room (no role), we just disconnected.
                // We do NOT want to auto-search or generate new hash if we were in a group call and left.
                // The hash clearing logic above handles the "exit room".
                // The role set to null handles "return to lobby".

                if (roleRef.current === "volunteer") {
                    if (typeof window !== "undefined") {
                        // Replace with a fresh waiting hash — volunteer goes back to lobby
                        // with a new identity so the old student's room isn't re-joined.
                        const newVolunteerHash = generateLinkHash()
                        window.history.replaceState(null, "", newVolunteerHash)
                        justClearedHash = false // hash is present; skip the re-generation below
                        log(
                            `Volunteer manual hangup - new waiting hash: ${newVolunteerHash}`
                        )
                    }
                }

                setRole(null)
                if (typeof window !== "undefined") {
                    // localStorage.removeItem("user_role") // No longer needed as we don't save it

                    // If no role, ensure we have a hash for Private Room Mode
                    // Force generation if we just cleared it as a volunteer
                    // BUT: If we just left a multi-party call (isMultiPartyHistory), maybe we don't want to auto-generate/search immediately?
                    // Requirement: "if you hang up from a private room of 3+, it shouldnt start auto-searching just bc u hanged up"
                    // If we clear hash, we are effectively "new".
                    // To prevent auto-search (passive MQTT), we might need a flag or just let the user see the "Start" screen.
                    // The "Start" screen appears when role is null.
                    // Passive MQTT starts automatically if there is a hash.

                    if (
                        justClearedHash ||
                        !window.location.hash ||
                        window.location.hash.length <= 1
                    ) {
                        // Only generate new hash if we are NOT coming from a multi-party exit where we intentionally want to stop.
                        // Actually, if we clear hash, we are just sitting on the page.
                        // We DO want a hash so they can share it for a NEW room.
                        const newHash = generateLinkHash()
                        window.history.replaceState(null, "", newHash)
                        log(
                            `No role reset - Generated new private room hash: ${newHash}`
                        )

                        // Restart passive MQTT since we now have a room
                        // UNLESS we just left a 3+ call (multi-party), then maybe we don't auto-start searching?
                        // "it shouldnt start auto-searching just bc u hanged up"
                        // Passive MQTT puts us in the lobby.
                        // If we want to prevent auto-search, we should NOT call initPassiveMQTT immediately.
                        // But we need a hash to be ready.

                        if (!isMultiPartyHistory) {
                            if (mqttClient.current) mqttClient.current.end()
                            setTimeout(() => initPassiveMQTT(), 100)
                        } else {
                            log(
                                "Exited multi-party call - skipping auto-init of passive MQTT to prevent immediate re-search"
                            )
                            // We still have a hash (newly generated), but we aren't broadcasting presence yet.
                            // User must click something to start?
                            // Currently there is no "Start" button for private room mode, it just runs.
                            // If we don't init MQTT, they are offline.
                            // We probably want them to be able to share the link.
                            // Let's just suppress the *search* part (active connection) but allow passive listening?
                            // initPassiveMQTT does both (subscribes).
                            // Let's respect the "don't start auto-searching" by skipping this.
                        }
                    }
                }
            } else {
                // Remote hangup (peer disconnected)

                // If I am a VOLUNTEER and student hung up, get a fresh waiting hash
                if (roleRef.current === "volunteer") {
                    if (typeof window !== "undefined") {
                        // Give the volunteer a new waiting hash so they're always identifiable
                        // while they wait for the next student. The old student's hash is gone.
                        const newVolunteerHash = generateLinkHash()
                        window.history.replaceState(null, "", newVolunteerHash)
                        log(
                            `Volunteer remote disconnect - new waiting hash: ${newVolunteerHash}`
                        )
                    }
                }

                // Not manual hangup (remote disconnect).
                // Preserve role for everyone (Student AND Volunteer) so they auto-queue.
                // We keep role in state (roleRef.current) which is enough for the session.
                // We do NOT save to localStorage anymore.
                /* 
                if (typeof window !== "undefined" && roleRef.current) {
                    localStorage.setItem("user_role", roleRef.current)
                }
                */
                // Refresh ID to prevent PeerJS "ID taken" errors on immediate reconnect
                myId.current = "user_" + Math.random().toString(36).substr(2, 6)
            }

            setLocalStream(null)
            setRemoteStream(null)
            setRemoteScreenStream(null)
            setIsScreenSharing(false) // Ensure screen share flag is cleared

            // Clear refs to prevent stale references
            localStreamRef.current = null
            remoteStreamRef.current = null
            activeCall.current = null
        },
        [isLiveMode, stopLiveSession]
    )

    const resetSilenceTimer = React.useCallback(() => {
        if (silenceTimerRef.current) clearTimeout(silenceTimerRef.current)
        silenceTimerRef.current = setTimeout(() => {
            log("AI Silence timeout (30s) - hanging up")
            cleanup()
        }, 30000)
    }, [cleanup])

    const startLiveSession = React.useCallback(async () => {
        log("startLiveSession called")
        haptic.medium()

        const liveModel = "models/gemini-3.1-flash-live-preview"
        log(`Using Live Model: ${liveModel}`)

        try {
            const tokenRes = await fetch(`${apiBase}/auth/gemini-token`)
            if (!tokenRes.ok) {
                log(`Gemini token fetch failed: ${tokenRes.status}`)
                return
            }
            const tokenJson = (await tokenRes.json()) as {
                token?: string
                error?: string
            }
            const liveToken = tokenJson.token
            if (!liveToken) {
                log("Missing ephemeral token from Worker")
                return
            }
            const url = `wss://generativelanguage.googleapis.com/ws/google.ai.generativelanguage.v1beta.GenerativeService.BidiGenerateContent?key=${encodeURIComponent(liveToken)}`
            const ws = new WebSocket(url)
            liveClientRef.current = ws

            ws.onopen = async () => {
                log("Connected to Gemini Live WebSocket")
                resetSilenceTimer()
                const docContext = isDocOpen
                    ? `\n\n[Current Document Content]:\n${docContent}`
                    : ""

                // BCP-47 locale from the browser (used for Live ASR/TTS per SpeechConfig).
                const deviceLanguageCode =
                    typeof navigator !== "undefined" &&
                    typeof navigator.language === "string" &&
                    navigator.language.length > 0
                        ? navigator.language
                        : "en-US"

                ws.send(
                    JSON.stringify({
                        setup: {
                            model: liveModel,
                            generationConfig: {
                                responseModalities: ["AUDIO"],
                                thinkingConfig: {
                                    thinkingLevel: "minimal",
                                },
                                speechConfig: {
                                    voiceConfig: {
                                        prebuiltVoiceConfig: {
                                            voiceName: "Puck",
                                        },
                                    },
                                    languageCode: deviceLanguageCode,
                                },
                            },
                            systemInstruction: {
                                parts: [
                                    // forVoice=true: strips delimiter instructions so the
                                    // model doesn't speak XML tag names aloud during the call.
                                    // Suggestions are handled via fetchAiSuggestions() instead.
                                    {
                                        text:
                                            getSystemPromptWithContext(true) +
                                            docContext,
                                    },
                                ],
                            },
                            tools: [
                                {
                                    functionDeclarations: [
                                        {
                                            name: "search_jobs",
                                            description:
                                                'Search Curastem job listings. If the user names a role, put it in query; if they want ANY role or all openings, OMIT query and keywords (use location, visa, company, etc. only). Never add seniority, stacks, or resume terms unless asked. Never concatenate many job titles into one query. Omit seniority_level unless they name a level. Expand abbreviations only (swe → software engineer). Umbrella asks: neutral roles and/or company slugs. Pass company when they name an employer. Visa when relevant. For two or more metros at once, use location_or or one location string with "or" between cities. Client excludes already-shown job IDs. Results as cards in chat.',
                                            parameters: {
                                                type: "OBJECT",
                                                properties: {
                                                    query: {
                                                        type: "STRING",
                                                        description:
                                                            "Job title or role phrase ONLY if they asked for a specific role. Sent as API title= (matches job title text only, not company). If they want any role / all jobs / no title preference, omit (empty). Never invent a title or merge many roles into one string.",
                                                    },
                                                    keywords: {
                                                        type: "STRING",
                                                        description:
                                                            "Extra tokens only if the user mentioned skills/stacks in this turn. Omit by default — do not pull keywords from saved resume or profile.",
                                                    },
                                                    company: {
                                                        type: "STRING",
                                                        description:
                                                            "Employer slug(s): one slug, or comma-separated for multiple companies (OR), e.g. meta,google,apple,amazon,netflix,microsoft for FAANG-style asks. Lowercase-hyphenated. If 0 results, retry without company.",
                                                    },
                                                    location: {
                                                        type: "STRING",
                                                        description:
                                                            'City or region as a short place name when you do not pass near_lat/near_lng. The API matches location substrings on postings. For "near me" the client uses GET /geo and IP only (no browser GPS). For multiple metros in one request, prefer location_or or a single string with "or" between places (e.g. San Francisco or New York).',
                                                    },
                                                    location_or: {
                                                        type: "STRING",
                                                        description:
                                                            'Comma-separated place names when the user names two or more metros in one turn. Matches jobs whose location contains ANY term (one API request). Example: San Francisco,New York. Omit when only one place or "near me".',
                                                    },
                                                    employment_type: {
                                                        type: "STRING",
                                                        description:
                                                            "full_time, part_time, contract, internship, or temporary",
                                                    },
                                                    workplace_type: {
                                                        type: "STRING",
                                                        description:
                                                            "remote, hybrid, or on_site",
                                                    },
                                                    seniority_level: {
                                                        type: "STRING",
                                                        description:
                                                            "Omit unless the user explicitly asked for a band (e.g. senior, entry level). Never infer from resume. Values: new_grad, entry, mid, senior, staff, manager, director, executive.",
                                                    },
                                                    posted_within_days: {
                                                        type: "NUMBER",
                                                        description:
                                                            "Optional: 1–30. Omit for newest-first listings with no hard date cutoff. Set only when the user asks to limit the time window (e.g. 7 this week, 30 this month).",
                                                    },
                                                    salary_min: {
                                                        type: "NUMBER",
                                                        description:
                                                            "Minimum annual salary (USD). Only returns jobs where salary is known and meets this threshold. E.g. 100000 for $100k+",
                                                    },
                                                    visa_sponsorship: {
                                                        type: "STRING",
                                                        description:
                                                            "Set 'yes' for jobs that sponsor work visas (user asks about H-1B, sponsorship, etc.). Set 'no' only if they want postings that explicitly say no sponsorship. Omit if not relevant.",
                                                    },
                                                    description_language: {
                                                        type: "STRING",
                                                        description:
                                                            "ISO 639-1 language of posting (en, es, de, etc.). Omit unless the user asks for a specific language.",
                                                    },
                                                    country: {
                                                        type: "STRING",
                                                        description:
                                                            "ISO 3166-1 alpha-2 country filter (US, GB, …). Jobs in that country or remote.",
                                                    },
                                                    exclude_ids: {
                                                        type: "STRING",
                                                        description:
                                                            "Comma-separated job IDs to skip (already shown).",
                                                    },
                                                    near_lat: {
                                                        type: "NUMBER",
                                                        description:
                                                            "User latitude for nearby jobs — use with near_lng when you supply coordinates yourself (optional; chat otherwise uses /geo + IP for near me).",
                                                    },
                                                    near_lng: {
                                                        type: "NUMBER",
                                                        description:
                                                            "User longitude — required with near_lat for distance search.",
                                                    },
                                                    radius_km: {
                                                        type: "NUMBER",
                                                        description:
                                                            "Search radius in km when using near_lat/near_lng. Default 50.",
                                                    },
                                                    exclude_remote: {
                                                        type: "BOOLEAN",
                                                        description:
                                                            "When searching near_lat/near_lng: false includes remote listings; true (default) keeps only local/on-site/hybrid with coords.",
                                                    },
                                                    limit: {
                                                        type: "NUMBER",
                                                        description:
                                                            "Number of results (default 6, max 20)",
                                                    },
                                                },
                                            },
                                        },
                                        {
                                            name: "get_job_details",
                                            description:
                                                "Get full details about a specific job. Use when the user asks about 'this job', 'that job', or wants to know more. If a job is currently open in the sidebar its ID is in the system context — use it directly.",
                                            parameters: {
                                                type: "OBJECT",
                                                properties: {
                                                    job_id: {
                                                        type: "STRING",
                                                        description:
                                                            "The job ID from a search result or from the currently viewed job context",
                                                    },
                                                },
                                                required: ["job_id"],
                                            },
                                        },
                                    ],
                                },
                            ],
                            inputAudioTranscription: {},
                            outputAudioTranscription: {},
                            // Sliding-window compression removes the 2-min audio+video
                            // session cap; sessions run until explicitly stopped.
                            contextWindowCompression: { slidingWindow: {} },
                            // Align input turns with speech activity (same scope the model uses for audio).
                            realtimeInputConfig: {
                                turnCoverage: "TURN_INCLUDES_ONLY_ACTIVITY",
                            },
                        },
                    })
                )

                const AudioContextClass =
                    window.AudioContext || (window as any).webkitAudioContext
                const audioCtx = new AudioContextClass()
                const audioCtxRef = audioCtx // Capture for closure use

                if (audioCtx.state === "suspended") {
                    await audioCtx.resume()
                }

                liveAudioContextRef.current = audioCtx
                liveNextPlayTimeRef.current = audioCtx.currentTime + 0.1

                try {
                    // Reuse any stream already acquired by handleConnectWithAI
                    // (which called getUserMedia inside the user-gesture handler —
                    // required on iOS Safari so the permission dialog appears).
                    // Only fall back to a new getUserMedia if no stream yet.
                    let stream = localStreamRef.current
                    if (!stream) {
                        // Same iOS audioSession fix as startChat()
                        if (
                            typeof navigator !== "undefined" &&
                            "audioSession" in navigator
                        ) {
                            ;(navigator as any).audioSession.type =
                                "play-and-record"
                        }
                        stream = await navigator.mediaDevices.getUserMedia({
                            video: true,
                            audio: {
                                sampleRate: 16000,
                                channelCount: 1,
                                echoCancellation: true,
                                noiseSuppression: true,
                                autoGainControl: true,
                                latency: 0.01,
                            } as any,
                        })
                        localStreamRef.current = stream
                        setLocalStream(stream)
                    }

                    liveInputStreamRef.current = stream
                    const source = audioCtx.createMediaStreamSource(stream)
                    liveSourceRef.current = source

                    const processor = audioCtx.createScriptProcessor(8192, 1, 1)
                    liveProcessorRef.current = processor

                    let consecutiveSpeechFrames = 0
                    const SPEECH_FRAMES_THRESHOLD = 2

                    processor.onaudioprocess = (e) => {
                        if (!liveClientRef.current) return
                        let inputData = e.inputBuffer.getChannelData(0)

                        // Threshold for Voice Activity Detection
                        // Lowered to 0.001 to detect normal speaking volume
                        const interruptionThreshold = 0.001

                        const isSpeaking = detectVoiceActivity(
                            inputData,
                            interruptionThreshold
                        )

                        if (isSpeaking) {
                            consecutiveSpeechFrames++
                            lastUserSpeechTimeRef.current = Date.now()

                            if (
                                consecutiveSpeechFrames >=
                                    SPEECH_FRAMES_THRESHOLD &&
                                !userIsSpeakingRef.current
                            ) {
                                userIsSpeakingRef.current = true
                                forceNewUserTranscriptBubbleRef.current = true
                                setUserIsSpeaking(true)
                                captureCurrentContext().then((b64) => {
                                    if (
                                        b64 &&
                                        ws.readyState === WebSocket.OPEN
                                    ) {
                                        ws.send(
                                            JSON.stringify({
                                                realtimeInput: {
                                                    video: {
                                                        mimeType: "image/jpeg",
                                                        data: b64,
                                                    },
                                                },
                                            })
                                        )
                                    }
                                })

                                // CAPTURE CONTEXT IMAGE
                                captureCurrentContext().then((b64) => {
                                    if (
                                        b64 &&
                                        liveClientRef.current &&
                                        liveClientRef.current.readyState ===
                                            WebSocket.OPEN
                                    ) {
                                        liveClientRef.current.send(
                                            JSON.stringify({
                                                realtimeInput: {
                                                    video: {
                                                        mimeType: "image/jpeg",
                                                        data: b64,
                                                    },
                                                },
                                            })
                                        )
                                    }
                                })
                            }
                        } else {
                            consecutiveSpeechFrames = 0
                            if (
                                userIsSpeakingRef.current &&
                                Date.now() - lastUserSpeechTimeRef.current > 500
                            ) {
                                userIsSpeakingRef.current = false
                                setUserIsSpeaking(false)
                            }
                        }

                        const downsampledData = downsampleBuffer(
                            inputData,
                            audioCtx.sampleRate,
                            INPUT_TARGET_SAMPLE_RATE
                        )

                        // HALLUCINATION FIX: Mute audio if no voice detected (Noise Gate)
                        // REMOVED: Native audio models are robust enough to handle background noise
                        // and this was causing users to have to scream to be heard.
                        /*
                        if (!userIsSpeakingRef.current && !isSpeaking) {
                            downsampledData.fill(0)
                        }
                        */

                        const b64 = float32ToBase64(downsampledData)

                        if (
                            ws.readyState === WebSocket.OPEN &&
                            b64.length > 0
                        ) {
                            ws.send(
                                JSON.stringify({
                                    realtimeInput: {
                                        audio: {
                                            mimeType: `audio/pcm;rate=${INPUT_TARGET_SAMPLE_RATE}`,
                                            data: b64,
                                        },
                                    },
                                })
                            )
                        }
                    }

                    source.connect(processor)
                    processor.connect(audioCtx.destination)
                } catch (err) {
                    console.error("Audio capture failed", err)
                    stopLiveSession()
                }
            }

            ws.onmessage = async (event) => {
                try {
                    let data
                    if (event.data instanceof Blob) {
                        data = JSON.parse(await event.data.text())
                    } else {
                        data = JSON.parse(event.data)
                    }

                    // Reset silence timer on any AI activity
                    if (
                        data.serverContent?.modelTurn ||
                        data.serverContent?.turnComplete
                    ) {
                        resetSilenceTimer()
                    }

                    if (data.serverContent?.interrupted) {
                        stopAllAudio()
                        isLiveGeneratingRef.current = false
                        setIsLiveGenerating(false)
                        return
                    }

                    if (data.serverContent?.modelTurn?.parts) {
                        isLiveGeneratingRef.current = true
                        setIsLiveGenerating(true)

                        suggestionsGeneratedForTurnRef.current = false

                        const parts = data.serverContent.modelTurn.parts
                        for (const part of parts) {
                            if (part.inlineData) {
                                if (
                                    liveAudioContextRef.current &&
                                    part.inlineData.data &&
                                    !data.serverContent?.turnComplete
                                ) {
                                    const audioCtx = liveAudioContextRef.current
                                    const float32 = base64ToFloat32Array(
                                        part.inlineData.data
                                    )
                                    const buffer = audioCtx.createBuffer(
                                        1,
                                        float32.length,
                                        MODEL_OUTPUT_SAMPLE_RATE
                                    )
                                    buffer.copyToChannel(float32, 0)

                                    const source = audioCtx.createBufferSource()
                                    source.buffer = buffer
                                    source.connect(audioCtx.destination)

                                    const now = audioCtx.currentTime
                                    const playTime = Math.max(
                                        now,
                                        liveNextPlayTimeRef.current
                                    )
                                    source.start(playTime)
                                    liveNextPlayTimeRef.current =
                                        playTime + buffer.duration

                                    activeAudioSourcesRef.current.push(source)

                                    // Start visual pulse when audio is queued
                                    setIsAiSpeaking(true)

                                    source.onended = () => {
                                        activeAudioSourcesRef.current =
                                            activeAudioSourcesRef.current.filter(
                                                (s) => s !== source
                                            )

                                        // If no more audio is playing AND the model is done generating (turn complete), stop visual
                                        if (
                                            activeAudioSourcesRef.current
                                                .length === 0 &&
                                            !isLiveGeneratingRef.current
                                        ) {
                                            setIsAiSpeaking(false)
                                        }
                                    }
                                }
                            }
                        }
                    }

                    if (data.serverContent?.turnComplete) {
                        isLiveGeneratingRef.current = false
                        setIsLiveGenerating(false)

                        // If no audio is currently playing, stop visual immediately
                        if (activeAudioSourcesRef.current.length === 0) {
                            setIsAiSpeaking(false)
                        }

                        if (transcriptionTimeoutRef.current) {
                            clearTimeout(transcriptionTimeoutRef.current)
                            transcriptionTimeoutRef.current = null
                        }

                        if (!suggestionsGeneratedForTurnRef.current) {
                            setMessages((prev) => {
                                const lastAssistantMsg = [...prev]
                                    .reverse()
                                    .find((m) => m.role === "assistant")

                                if (
                                    lastAssistantMsg &&
                                    lastAssistantMsg.text.trim()
                                ) {
                                    fetchAiSuggestions(
                                        lastAssistantMsg.text.trim()
                                    )
                                }
                                return prev
                            })
                        }
                    }

                    // ---------------------------------------------------------------------------
                    // Handle tool calls from Gemini Live (search_jobs, get_job_details)
                    // The model sends a toolCall message; we execute the function and reply
                    // with toolResponse so the model can continue speaking.
                    // ---------------------------------------------------------------------------
                    if (data.toolCall?.functionCalls?.length) {
                        for (const fc of data.toolCall.functionCalls) {
                            ;(async () => {
                                let responsePayload: any = {}

                                if (fc.name === "search_jobs") {
                                    const args = fc.args ?? {}
                                    const params = new URLSearchParams()
                                    const titleMerged = buildJobsApiTitle(
                                        args.query,
                                        args.keywords
                                    )
                                    if (titleMerged)
                                        params.set("title", titleMerged)
                                    if (args.company)
                                        params.set("company", args.company)
                                    {
                                        const locOrLive =
                                            deriveLocationOrForJobsParams(args)
                                        if (locOrLive) {
                                            params.set("location_or", locOrLive)
                                        } else if (args.location) {
                                            params.set(
                                                "location",
                                                args.location
                                            )
                                        }
                                    }
                                    if (args.employment_type)
                                        params.set(
                                            "employment_type",
                                            args.employment_type
                                        )
                                    if (args.workplace_type)
                                        params.set(
                                            "workplace_type",
                                            args.workplace_type
                                        )
                                    if (args.seniority_level)
                                        params.set(
                                            "seniority_level",
                                            args.seniority_level
                                        )
                                    {
                                        const sinceLive =
                                            postedSinceUnixFromSearchJobsArg(
                                                args.posted_within_days
                                            )
                                        if (sinceLive != null) {
                                            params.set(
                                                "since",
                                                String(sinceLive)
                                            )
                                        }
                                    }
                                    if (args.salary_min != null)
                                        params.set(
                                            "salary_min",
                                            String(args.salary_min)
                                        )
                                    if (
                                        args.visa_sponsorship === "yes" ||
                                        args.visa_sponsorship === "no"
                                    )
                                        params.set(
                                            "visa_sponsorship",
                                            args.visa_sponsorship
                                        )
                                    if (args.description_language)
                                        params.set(
                                            "description_language",
                                            args.description_language
                                        )
                                    if (args.country)
                                        params.set(
                                            "country",
                                            String(args.country)
                                                .toUpperCase()
                                                .slice(0, 2)
                                        )
                                    if (
                                        args.near_lat != null &&
                                        !Number.isNaN(Number(args.near_lat))
                                    )
                                        params.set(
                                            "near_lat",
                                            String(args.near_lat)
                                        )
                                    if (
                                        args.near_lng != null &&
                                        !Number.isNaN(Number(args.near_lng))
                                    )
                                        params.set(
                                            "near_lng",
                                            String(args.near_lng)
                                        )
                                    if (args.radius_km != null)
                                        params.set(
                                            "radius_km",
                                            String(args.radius_km)
                                        )
                                    if (args.exclude_remote === false)
                                        params.set("exclude_remote", "false")
                                    applySearchJobsExcludeIds(
                                        params,
                                        searchJobsSeenJobIdsRef.current,
                                        args.exclude_ids
                                    )
                                    params.set(
                                        "limit",
                                        String(Math.min(args.limit ?? 6, 20))
                                    )
                                    await applySearchJobsGeoResolution(
                                        params,
                                        args,
                                        liveUserUtteranceForGeoRef.current,
                                        ipGeoFromLocationInfo(locationInfo),
                                        { jobsProxyGeoRef },
                                        jobsApiUrl
                                    )
                                    if (debugPanelRef.current === "tools") {
                                        try {
                                            log(
                                                `[live tool] search_jobs args=${JSON.stringify(args)}`,
                                                "tools"
                                            )
                                        } catch {
                                            log(
                                                "[live tool] search_jobs (args not serializable)",
                                                "tools"
                                            )
                                        }
                                        log(
                                            `[live tool] GET ${jobsApiUrl}/jobs?${params.toString()}`,
                                            "tools"
                                        )
                                    }
                                    try {
                                        const jobsRes = await fetch(
                                            `${jobsApiUrl}/jobs?${params}`
                                        )
                                        if (debugPanelRef.current === "tools") {
                                            log(
                                                `[live tool] search_jobs HTTP ${jobsRes.status}`,
                                                "tools"
                                            )
                                        }
                                        if (jobsRes.ok) {
                                            const jobsData =
                                                await jobsRes.json()
                                            const rows = dedupeJobRowsById(
                                                jobsData.data
                                            )
                                            const snippets: JobSnippet[] =
                                                rows.map(
                                                    (j: any): JobSnippet => ({
                                                        id: j.id,
                                                        title: j.title,
                                                        company:
                                                            j.company?.name ??
                                                            "",
                                                        company_logo:
                                                            j.company
                                                                ?.logo_url ??
                                                            null,
                                                        locations:
                                                            j.locations ?? null,
                                                        employment_type:
                                                            j.employment_type ??
                                                            null,
                                                        workplace_type:
                                                            j.workplace_type ??
                                                            null,
                                                        seniority_level:
                                                            j.seniority_level ??
                                                            null,
                                                        posted_at:
                                                            j.posted_at ?? null,
                                                        apply_url:
                                                            j.apply_url ?? null,
                                                        summary:
                                                            j.job_summary ??
                                                            null,
                                                        salary:
                                                            j.salary?.display ??
                                                            null,
                                                        visa_sponsorship:
                                                            j.visa_sponsorship ??
                                                            null,
                                                    })
                                                )
                                            recordSearchJobsShownIds(
                                                searchJobsSeenJobIdsRef.current,
                                                snippets
                                            )
                                            if (
                                                debugPanelRef.current ===
                                                "tools"
                                            ) {
                                                log(
                                                    `[live tool] search_jobs rows=${snippets.length}`,
                                                    "tools"
                                                )
                                            }
                                            // Show cards in chat
                                            if (snippets.length > 0) {
                                                setMessages((prev) => [
                                                    ...prev,
                                                    {
                                                        role: "model",
                                                        text: "",
                                                        jobs: snippets,
                                                    },
                                                ])
                                            }
                                            responsePayload = {
                                                jobs: snippets
                                                    .slice(0, 6)
                                                    .map(
                                                        (j, i) =>
                                                            `${i + 1}. ${j.title} at ${j.company}${j.locations?.[0] ? ` — ${j.locations[0]}` : ""}`
                                                    )
                                                    .join("\n"),
                                                total: snippets.length,
                                            }
                                        }
                                    } catch (err) {
                                        console.error(
                                            "live search_jobs fetch:",
                                            err
                                        )
                                        responsePayload = {
                                            error: "Could not reach jobs API.",
                                        }
                                    }
                                } else if (fc.name === "get_job_details") {
                                    const jobId =
                                        fc.args?.job_id ||
                                        selectedJobRef.current?.id ||
                                        null
                                    if (jobId) {
                                        try {
                                            // Serve from cache when available — avoids a redundant round-trip
                                            // for jobs the panel already loaded.
                                            const cached = readJobDetailCache(
                                                jobId,
                                                jobsApiUrl
                                            )
                                            // Only serve from cache when AI enrichment is confirmed done;
                                            // otherwise fetch fresh so the AI gets the latest enriched data.
                                            const j: any = cached?.aiDone
                                                ? {
                                                      job_description:
                                                          cached.desc,
                                                      job_summary:
                                                          cached.detailSummary,
                                                      visa_sponsorship:
                                                          cached.detailVisaSponsorship,
                                                      company: {
                                                          description:
                                                              cached.detailCompanyDesc,
                                                      },
                                                      keywords:
                                                          cached.apiKeywords,
                                                      experience_years_min:
                                                          cached.detailExperienceYearsMin,
                                                      job_city:
                                                          cached.detailJobCity,
                                                      job_state:
                                                          cached.detailJobState,
                                                      job_country:
                                                          cached.detailJobCountry,
                                                  }
                                                : await fetch(
                                                      `${jobsApiUrl}/jobs/${jobId}`
                                                  ).then((r) =>
                                                      r.ok ? r.json() : null
                                                  )
                                            if (j) {
                                                responsePayload = {
                                                    title: j.title,
                                                    company: j.company?.name,
                                                    locations:
                                                        j.locations ?? null,
                                                    employment_type:
                                                        j.employment_type,
                                                    workplace_type:
                                                        j.workplace_type,
                                                    summary: j.job_summary,
                                                    salary: j.salary,
                                                    responsibilities:
                                                        j.job_description
                                                            ?.responsibilities ??
                                                        [],
                                                    minimum_qualifications:
                                                        j.job_description
                                                            ?.minimum_qualifications ??
                                                        [],
                                                    apply_url: j.apply_url,
                                                }
                                            }
                                        } catch (err) {
                                            console.error(
                                                "live get_job_details:",
                                                err
                                            )
                                            responsePayload = {
                                                error: "Could not retrieve job details.",
                                            }
                                        }
                                    } else {
                                        responsePayload = {
                                            error: "No job ID provided.",
                                        }
                                    }
                                }

                                // Send tool response back so the model can speak its answer
                                if (ws.readyState === WebSocket.OPEN) {
                                    ws.send(
                                        JSON.stringify({
                                            toolResponse: {
                                                functionResponses: [
                                                    {
                                                        id: fc.id,
                                                        response:
                                                            responsePayload,
                                                    },
                                                ],
                                            },
                                        })
                                    )
                                }
                            })()
                        }
                    }

                    if (data.serverContent?.outputTranscription?.text) {
                        const rawText =
                            data.serverContent.outputTranscription.text

                        // Safety net: strip any <curastem-*> tags that leaked into the
                        // audio transcription. This should not happen with forVoice=true
                        // system prompt, but guards against stale sessions or API quirks.
                        const text = rawText
                            .replace(
                                /<curastem-[^>]*>[\s\S]*?<\/curastem-[^>]*>/g,
                                ""
                            )
                            .replace(/<\/?curastem-[^>]*>/g, "")

                        if (transcriptionTimeoutRef.current) {
                            clearTimeout(transcriptionTimeoutRef.current)
                        }

                        transcriptionTimeoutRef.current = setTimeout(() => {
                            if (!suggestionsGeneratedForTurnRef.current) {
                                setMessages((prev) => {
                                    const lastAssistantMsg = [...prev]
                                        .reverse()
                                        .find((m) => m.role === "assistant")

                                    if (
                                        lastAssistantMsg &&
                                        lastAssistantMsg.text.trim()
                                    ) {
                                        fetchAiSuggestions(
                                            lastAssistantMsg.text.trim()
                                        )
                                        suggestionsGeneratedForTurnRef.current = true
                                    }
                                    return prev
                                })
                            }
                        }, 800)

                        React.startTransition(() => {
                            setMessages((prev) => {
                                const last = prev[prev.length - 1]
                                if (last && last.role === "assistant") {
                                    return [
                                        ...prev.slice(0, -1),
                                        {
                                            ...last,
                                            text: last.text + text,
                                        },
                                    ]
                                }
                                return [
                                    ...prev,
                                    { role: "assistant", text: text },
                                ]
                            })
                        })
                    }

                    if (data.serverContent?.inputTranscription?.text) {
                        const text = data.serverContent.inputTranscription.text

                        React.startTransition(() => {
                            setMessages((prev) => {
                                const last = prev[prev.length - 1]

                                if (last?.role === "user") {
                                    forceNewUserTranscriptBubbleRef.current = false
                                    liveUserUtteranceForGeoRef.current += text
                                    return [
                                        ...prev.slice(0, -1),
                                        {
                                            ...last,
                                            text: (last.text || "") + text,
                                        },
                                    ]
                                }

                                // Late input ASR can arrive after modelTurn (ordering is not guaranteed).
                                // Merge into the preceding user bubble while the assistant reply is still
                                // generating or playing; otherwise open a new user message.
                                const responseStillPlaying =
                                    isLiveGeneratingRef.current ||
                                    activeAudioSourcesRef.current.length > 0

                                if (
                                    last?.role === "assistant" &&
                                    responseStillPlaying &&
                                    !forceNewUserTranscriptBubbleRef.current
                                ) {
                                    let userIdx = -1
                                    for (let i = prev.length - 1; i >= 0; i--) {
                                        if (prev[i].role === "user") {
                                            userIdx = i
                                            break
                                        }
                                    }
                                    if (userIdx >= 0) {
                                        liveUserUtteranceForGeoRef.current +=
                                            text
                                        const next = [...prev]
                                        const u = next[userIdx]
                                        next[userIdx] = {
                                            ...u,
                                            text: (u.text || "") + text,
                                        }
                                        return next
                                    }
                                }

                                forceNewUserTranscriptBubbleRef.current = false
                                liveUserUtteranceForGeoRef.current = text
                                return [...prev, { role: "user", text }]
                            })
                        })
                    }
                } catch (e) {
                    console.error("WS Parse Error", e)
                }
            }

            ws.onclose = (ev) => {
                log(
                    `Gemini WebSocket Closed: Code=${ev.code}, Reason=${ev.reason}, WasClean=${ev.wasClean}`
                )
                stopLiveSession()
            }

            ws.onerror = (e) => {
                log("Gemini WebSocket Error Event")
                // Extract useful error info if possible
                // @ts-ignore
                if (e.message) log(`WS Error message: ${e.message}`)
                console.error(e)
                stopLiveSession()
            }

            setIsLiveMode(true)
            setStatus("connected") // Connected to AI
            log("Live Mode Enabled. Status set to 'connected'")
        } catch (e) {
            log(`Live Init Exception: ${e}`)
            console.error("Live Init Error", e)
            stopLiveSession()
        }
    }, [
        apiBase,
        getSystemPromptWithContext,
        isDocOpen,
        docContent,
        stopLiveSession,
        fetchAiSuggestions,
        captureCurrentContext,
    ])

    const handleConnectWithAI = React.useCallback(() => {
        log(`handleConnectWithAI clicked. Status: ${status}, Role: ${role}`)
        playCallStartSound()
        startLiveSession()
    }, [startLiveSession, status, role])

    // Cleanup on unmount
    React.useEffect(() => {
        return () => {
            stopLiveSession()
        }
    }, [stopLiveSession])

    // --- STATE: DEBUGGING ---
    const [p2pLogs, setP2pLogs] = React.useState<string[]>([])
    const [toolLogs, setToolLogs] = React.useState<string[]>([])
    const [showReportModal, setShowReportModal] = React.useState(false)
    const [reportType, setReportType] = React.useState<"user" | "chat">("user")
    const [isBanned, setIsBanned] = React.useState(false)

    // --- BAN SYSTEM LOGIC ---
    const checkBanStatus = React.useCallback(() => {
        if (typeof window === "undefined") return false

        const expiry = localStorage.getItem("curastem_ban_expiry")
        if (expiry) {
            const remaining = parseInt(expiry) - Date.now()
            if (remaining > 0) {
                if (!isBanned) setIsBanned(true)
                return true
            } else {
                localStorage.removeItem("curastem_ban_expiry")
                if (isBanned) setIsBanned(false)
            }
        }
        return false
    }, [isBanned])

    React.useEffect(() => {
        checkBanStatus()
        const interval = setInterval(checkBanStatus, 1000)
        return () => clearInterval(interval)
    }, [checkBanStatus])

    // Effect to enforce ban (disconnect if active)
    React.useEffect(() => {
        if (isBanned && status !== "idle") {
            log("User is banned, disconnecting active session...")
            // We need to be careful not to create a loop if cleanup changes status
            // But cleanup() sets status to idle, so this should only run once
            if (activeCall.current) activeCall.current.close()
            if (dataConnectionRef.current) dataConnectionRef.current.close()
            if (localStreamRef.current) {
                localStreamRef.current.getTracks().forEach((t) => t.stop())
                localStreamRef.current = null
                setLocalStream(null)
            }
            setStatus("idle")
            setRole(null) // Reset role to force re-entry logic if desired
        }
    }, [isBanned, status])

    type LogChannel = "p2p" | "tools"

    /** On-screen + optional console mirror; tool/MCP lines go to the Tools buffer only. */
    const log = (msg: string, channel: LogChannel = "p2p") => {
        const line = `[${new Date().toLocaleTimeString()}] ${msg}`
        if (channel === "tools") {
            setToolLogs((prev) => [...prev.slice(-199), line])
            if (debugPanelRef.current === "tools")
                console.log(`[Curastem tools] ${msg}`)
        } else {
            setP2pLogs((prev) => [...prev.slice(-199), line])
            if (debugPanelRef.current === "p2p")
                console.log(`[Curastem p2p] ${msg}`)
        }
    }

    /** Tools & MCP panel: deduped /jobs homepage fetch URLs (with profile job title for context). */
    const homepageJobsQueryLoggedRef = React.useRef<Set<string>>(new Set())
    React.useEffect(() => {
        homepageJobsQueryLoggedRef.current.clear()
    }, [jobsApiUrl, debouncedYouWork])
    const logRefForHomepageJobs = React.useRef(log)
    React.useEffect(() => {
        logRefForHomepageJobs.current = log
    }, [log])
    const debouncedYouWorkHomepageDebugRef = React.useRef(debouncedYouWork)
    React.useEffect(() => {
        debouncedYouWorkHomepageDebugRef.current = debouncedYouWork
    }, [debouncedYouWork])
    const emitHomepageJobsQuery = React.useCallback((url: string, rowCount: number) => {
        if (homepageJobsQueryLoggedRef.current.has(url)) return
        homepageJobsQueryLoggedRef.current.add(url)
        const t = debouncedYouWorkHomepageDebugRef.current.trim()
        logRefForHomepageJobs.current(
            `[jobs homepage]${t ? ` title="${t}"` : ""} ${rowCount} rows ${url}`,
            "tools"
        )
    }, [])

    /** Tools panel: GET /jobs/map — deduped by center+filters (not full bbox) to avoid idle spam. */
    const mapJobsQueryLoggedRef = React.useRef<Set<string>>(new Set())
    React.useEffect(() => {
        mapJobsQueryLoggedRef.current.clear()
    }, [jobsApiUrl, isMapOpen])
