    const [homepageJobsForDeck, setHomepageJobsForDeck] = React.useState<
        HomepageJob[]
    >([])
    const [jobDeckExtras, setJobDeckExtras] = React.useState<HomepageJob[]>([])

    const jobCycleDeck = React.useMemo(() => {
        const seen = new Set<string>()
        const out: HomepageJob[] = []
        const push = (j: HomepageJob | null | undefined) => {
            if (!j?.id || seen.has(j.id)) return
            seen.add(j.id)
            out.push(j)
        }
        for (const j of homepageJobsForDeck) push(j)
        for (const msg of messages) {
            if (!msg.jobs?.length) continue
            for (const s of msg.jobs) push(jobSnippetToHomepageJob(s))
        }
        for (const j of jobDeckExtras) push(j)
        return out
    }, [messages, homepageJobsForDeck, jobDeckExtras])

    const handleHomepageDeckJobs = React.useCallback((jobs: HomepageJob[]) => {
        setHomepageJobsForDeck(jobs)
    }, [])

    const cycleJobDetail = React.useCallback(
        (delta: number) => {
            if (jobCycleDeck.length === 0) return
            const idx = jobCycleDeck.findIndex((j) => j.id === selectedJob?.id)
            const n = jobCycleDeck.length
            const base = idx >= 0 ? idx : 0
            const next = (((base + delta) % n) + n) % n
            const nextJob = jobCycleDeck[next]!
            setSelectedJob(nextJob)
            haptic.light()
            // Sync swipe/arrow navigation to peers
            dataConnectionsRef.current.forEach((conn) => {
                if (conn.open)
                    conn.send({ type: "job-cycle", payload: nextJob })
            })
        },
        [jobCycleDeck, selectedJob?.id]
    )

    const openJobDetail = React.useCallback(
        (job: HomepageJob) => {
            setJobDeckExtras((prev) => {
                if (prev.some((j) => j.id === job.id)) return prev
                const inHome = homepageJobsForDeck.some((j) => j.id === job.id)
                const inMsg = messages.some((m) =>
                    m.jobs?.some((s) => s.id === job.id)
                )
                if (inHome || inMsg) return prev
                return [...prev, job]
            })
            setSelectedJob(job)
            setIsJobOpen(true)
            setIsDocOpen(false)
            setIsWhiteboardOpen(false)
            setIsAppOpen(false)
            // Push ?job=<id> into the URL — preserves any existing ?map or ?settings params
            // so shared links like /?map&job=<id> open both panels correctly.
            if (typeof window !== "undefined") {
                if (!originalDocTitleRef.current)
                    originalDocTitleRef.current = document.title
                const url = new URL(window.location.href)
                if (url.searchParams.get("job") !== job.id) {
                    url.searchParams.set("job", job.id)
                    window.history.pushState(
                        { job: job.id },
                        "",
                        url.toString()
                    )
                }
                document.title = `${job.title} at ${job.company.name} | Curastem`
            }
            // Sync the open job panel to all connected peers
            dataConnectionsRef.current.forEach((conn) => {
                if (conn.open) conn.send({ type: "job-open", payload: job })
            })
        },
        [homepageJobsForDeck, messages]
    )

    /** Merge GET /jobs/:id fields into the open job + deck copies so header/map stay fresh. */
    const mergeJobFieldsFromDetail = React.useCallback(
        (jobId: string, fields: Partial<HomepageJob>) => {
            setSelectedJob((prev) =>
                prev?.id === jobId ? { ...prev, ...fields } : prev
            )
            setJobDeckExtras((prev) =>
                prev.map((j) => (j.id === jobId ? { ...j, ...fields } : j))
            )
            setHomepageJobsForDeck((prev) =>
                prev.map((j) => (j.id === jobId ? { ...j, ...fields } : j))
            )
        },
        []
    )

    React.useEffect(() => {
        if (!isJobOpen || jobCycleDeck.length < 2) return
        const onKey = (e: KeyboardEvent) => {
            if (e.key !== "ArrowLeft" && e.key !== "ArrowRight") return
            const el = document.activeElement as HTMLElement | null
            if (el?.closest("input, textarea, select, [contenteditable=true]"))
                return
            e.preventDefault()
            cycleJobDetail(e.key === "ArrowRight" ? 1 : -1)
        }
        window.addEventListener("keydown", onKey)
        return () => window.removeEventListener("keydown", onKey)
    }, [isJobOpen, jobCycleDeck.length, cycleJobDetail])

    // Hydrate job panel from ?job=<id> on first mount so shared / bookmarked
